import re
import os
from abc import ABC, abstractmethod
from typing import List

class FileProcessStrategy(ABC):
    @abstractmethod
    def process_file(self, original_name: str) -> str:
        pass

class RegexRenameStrategy(FileProcessStrategy):
    def __init__(self, pattern: str, replacement: str):
        self.pattern = pattern
        self.replacement = replacement

    def process_file(self, original_name: str) -> str:
        return re.sub(self.pattern, self.replacement, original_name)

class BulkFileRenamer:
    def __init__(self, strategy: FileProcessStrategy):
        self.strategy = strategy

    def rename_files(self, directory: str) -> List[str]:
        renamed_files = []
        for filename in os.listdir(directory):
            original_path = os.path.join(directory, filename)
            if os.path.isfile(original_path):
                new_name = self.strategy.process_file(filename)
                new_path = os.path.join(directory, new_name)
                os.rename(original_path, new_path)
                renamed_files.append((filename, new_name))
        return renamed_files

if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="Bulk rename files using regex patterns.")
    parser.add_argument("directory", help="Directory containing files to rename")
    parser.add_argument("--pattern", required=True, help="Regex pattern to match")
    parser.add_argument("--replacement", required=True, help="Replacement string")

    args = parser.parse_args()

    strategy = RegexRenameStrategy(args.pattern, args.replacement)
    renamer = BulkFileRenamer(strategy)
    result = renamer.rename_files(args.directory)

    for old, new in result:
        print(f"Renamed: {old} -> {new}")
