from typing import Callable, Dict

class CacheStrategy:
    def get(self, n: int) -> int:
        pass

    def set(self, n: int, value: int) -> None:
        pass

class DictCacheStrategy(CacheStrategy):
    def __init__(self):
        self.cache: Dict[int, int] = {}

    def get(self, n: int) -> int:
        return self.cache.get(n)

    def set(self, n: int, value: int) -> None:
        self.cache[n] = value

def fibonacci(n: int, cache_strategy: CacheStrategy) -> int:
    if n <= 1:
        return n

    cached = cache_strategy.get(n)
    if cached is not None:
        return cached

    result = fibonacci(n - 1, cache_strategy) + fibonacci(n - 2, cache_strategy)
    cache_strategy.set(n, result)
    return result
