from enum import Enum, auto


class TcpState(Enum):
    CLOSED = auto()
    LISTEN = auto()
    SYN_SENT = auto()
    SYN_RECEIVED = auto()
    ESTABLISHED = auto()
    FIN_WAIT_1 = auto()
    FIN_WAIT_2 = auto()
    CLOSE_WAIT = auto()
    CLOSING = auto()
    LAST_ACK = auto()
    TIME_WAIT = auto()


class TcpStateMachine:
    def __init__(self):
        self.current_state = TcpState.CLOSED

    def process_event(self, event):
        if self.current_state == TcpState.CLOSED:
            self._handle_closed(event)
        elif self.current_state == TcpState.LISTEN:
            self._handle_listen(event)
        elif self.current_state == TcpState.SYN_SENT:
            self._handle_syn_sent(event)
        elif self.current_state == TcpState.SYN_RECEIVED:
            self._handle_syn_received(event)
        elif self.current_state == TcpState.ESTABLISHED:
            self._handle_established(event)

    def _handle_closed(self, event):
        if event == "passive_open":
            self.current_state = TcpState.LISTEN
        elif event == "active_open":
            self.current_state = TcpState.SYN_SENT

    def _handle_listen(self, event):
        if event == "send_syn":
            self.current_state = TcpState.SYN_SENT
        elif event == "receive_syn":
            self.current_state = TcpState.SYN_RECEIVED

    def _handle_syn_sent(self, event):
        if event == "receive_syn_ack":
            self.current_state = TcpState.ESTABLISHED
        elif event == "receive_syn":
            self.current_state = TcpState.SYN_RECEIVED

    def _handle_syn_received(self, event):
        if event == "receive_ack":
            self.current_state = TcpState.ESTABLISHED

    def _handle_established(self, event):
        if event == "send_fin":
            self.current_state = TcpState.FIN_WAIT_1
        elif event == "receive_fin":
            self.current_state = TcpState.CLOSE_WAIT
