import numpy as np

class OptimizerStrategy:
    def update(self, params, grads):
        raise NotImplementedError

class GradientDescentOptimizer(OptimizerStrategy):
    def __init__(self, learning_rate=0.01):
        self.learning_rate = learning_rate

    def update(self, params, grads):
        return [param - self.learning_rate * grad for param, grad in zip(params, grads)]

class Optimizer:
    def __init__(self, strategy: OptimizerStrategy):
        self.strategy = strategy

    def optimize(self, params, grads):
        return self.strategy.update(params, grads)
