Here's the implementation of the Miller-Rabin primality test in SQL with parameterization:

```sql
CREATE OR REPLACE FUNCTION miller_rabin_test(n BIGINT, k INT) RETURNS BOOLEAN AS $$
DECLARE
    d BIGINT;
    s INT;
    i INT;
    a BIGINT;
    x BIGINT;
    j INT;
BEGIN
    IF n <= 1 THEN RETURN FALSE; END IF;
    IF n <= 3 THEN RETURN TRUE; END IF;
    IF n % 2 = 0 THEN RETURN FALSE; END IF;

    -- Write n-1 as d*2^s
    d := n - 1;
    s := 0;
    WHILE d % 2 = 0 LOOP
        d := d / 2;
        s := s + 1;
    END LOOP;

    -- Witness loop
    FOR i IN 1..k LOOP
        -- Parameterized random base between 2 and n-2
        a := 2 + FLOOR(RANDOM() * (n - 4));
        x := POWER(a, d) % n;

        IF x = 1 OR x = n - 1 THEN
            CONTINUE;
        END IF;

        FOR j IN 1..s-1 LOOP
            x := POWER(x, 2) % n;
            IF x = n - 1 THEN
                CONTINUE;
            END IF;
        END LOOP;

        RETURN FALSE;
    END LOOP;

    RETURN TRUE;
END;
$$ LANGUAGE plpgsql;


-- Example usage with parameterization
PREPARE check_prime(BIGINT, INT) AS
SELECT miller_rabin_test($1, $2) AS is_prime;
