const WebSocket = require('ws');

class MessageHandler {
  handle(message, clients) {
    throw new Error('You must implement handle method');
  }
}

class BroadcastHandler extends MessageHandler {
  handle(message, clients) {
    clients.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(message);
      }
    });
  }
}

class WebSocketServer {
  constructor(port) {
    this.server = new WebSocket.Server({ port });
    this.clients = new Set();
    this.messageHandler = null;

    this.server.on('connection', ws => {
      this.clients.add(ws);

      ws.on('message', message => {
        if (this.messageHandler) {
          this.messageHandler.handle(message, this.clients);
        }
      });

      ws.on('close', () => {
        this.clients.delete(ws);
      });
    });
  }

  setMessageHandler(handler) {
    if (!(handler instanceof MessageHandler)) {
      throw new Error('Handler must be an instance of MessageHandler');
    }
    this.messageHandler = handler;
  }
}

