import redis
import threading
import time

class PubSubSystem:
    def __init__(self, broker_type='redis', redis_host='localhost', redis_port=6379):
        self.broker_type = broker_type
        if broker_type == 'redis':
            self.redis_client = redis.Redis(host=redis_host, port=redis_port)
        elif broker_type == 'kafka':
            from kafka import KafkaProducer, KafkaConsumer
            self.kafka_producer = KafkaProducer(bootstrap_servers=f'{redis_host}:{redis_port}')
            self.kafka_consumers = {}
        self.subscribers = {}
        self.lock = threading.Lock()

    def publish(self, topic, message):
        if self.broker_type == 'redis':
            self.redis_client.xadd(topic, {'message': message})
        elif self.broker_type == 'kafka':
            self.kafka_producer.send(topic, value=message.encode('utf-8'))

    def subscribe(self, topic, callback):
        if self.broker_type == 'redis':
            def redis_listener():
                last_id = '0-0'
                while True:
                    messages = self.redis_client.xread({topic: last_id}, count=1, block=0)
                    if messages:
                        for message in messages[0][1]:
                            last_id = message[0]
                            callback(message[1][b'message'].decode('utf-8'))
            threading.Thread(target=redis_listener, daemon=True).start()
        elif self.broker_type == 'kafka':
            def kafka_listener():
                consumer = self.kafka_consumers.get(topic)
                if not consumer:
                    consumer = KafkaConsumer(
                        topic,
                        bootstrap_servers=self.kafka_producer.config['bootstrap_servers'],
                        auto_offset_reset='earliest',
                        enable_auto_commit=True,
                        group_id=f'{topic}-group'
                    )
                    self.kafka_consumers[topic] = consumer
                for msg in consumer:
                    callback(msg.value.decode('utf-8'))
            threading.Thread(target=kafka_listener, daemon=True).start()

    def unsubscribe(self, topic):
        if self.broker_type == 'kafka':
            consumer = self.kafka_consumers.get(topic)
            if consumer:
                consumer.close()
                del self.kafka_consumers[topic]

# Example usage:
# pubsub = PubSubSystem(broker_type='redis')
# pubsub.subscribe('test_topic', lambda msg: print(f"Received: {msg}"))
# pubsub.publish('test_topic', 'Hello, World!')
# time.sleep(1)
