import argparse
import os
from PIL import Image
from tqdm import tqdm

def validate_path(path):
    if not os.path.exists(path):
        raise ValueError(f"Path does not exist: {path}")
    return path

def validate_dimension(dim):
    try:
        dim = int(dim)
        if dim <= 0:
            raise ValueError("Dimensions must be positive integers")
        return dim
    except ValueError:
        raise ValueError("Dimensions must be positive integers")

def resize_image(input_path, output_path, width, height):
    try:
        with Image.open(input_path) as img:
            img = img.resize((width, height), Image.LANCZOS)
            img.save(output_path)
    except Exception as e:
        raise ValueError(f"Failed to resize image: {e}")

def main():
    parser = argparse.ArgumentParser(
        description="Bulk Image Resizer - Resize multiple images with ease.",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter
    )
    parser.add_argument(
        "-i", "--input",
        required=True,
        type=validate_path,
        help="Input directory or file path"
    )
    parser.add_argument(
        "-o", "--output",
        required=True,
        help="Output directory path"
    )
    parser.add_argument(
        "-w", "--width",
        required=True,
        type=validate_dimension,
        help="Target width in pixels"
    )
    parser.add_argument(
        "-h", "--height",
        required=True,
        type=validate_dimension,
        help="Target height in pixels"
    )
    parser.add_argument(
        "--prefix",
        default="resized_",
        help="Prefix for output filenames"
    )

    args = parser.parse_args()

    if not os.path.exists(args.output):
        os.makedirs(args.output)

    input_paths = []
    if os.path.isfile(args.input):
        input_paths.append(args.input)
    else:
        for root, _, files in os.walk(args.input):
            for file in files:
                if file.lower().endswith(('.png', '.jpg', '.jpeg', '.bmp', '.gif')):
                    input_paths.append(os.path.join(root, file))

    if not input_paths:
        raise ValueError("No valid image files found in the input path")

    errors = []
    for input_path in tqdm(input_paths, desc="Resizing images"):
        try:
            filename = os.path.basename(input_path)
            output_path = os.path.join(args.output, f"{args.prefix}{filename}")
            resize_image(input_path, output_path, args.width, args.height)
        except Exception as e:
            errors.append(f"{input_path}: {str(e)}")

    if errors:
        print("\nErrors encountered:")
        for error in errors:
            print(f"  - {error}")
    else:
        print("\nAll images resized successfully!")

if __name__ == "__main__":
    try:
        main()
    except Exception as e:
        print(f"Error: {str(e)}")
