import redis
import os
import secrets
import time
from typing import Optional, Dict, Any

class SecureRedisSessionStore:
    def __init__(self, host: str = 'localhost', port: int = 6379, db: int = 0, 
                 expire_seconds: int = 3600, secret_key: Optional[str] = None):
        self.redis = redis.StrictRedis(host=host, port=port, db=db)
        self.expire_seconds = expire_seconds
        self.secret_key = secret_key or os.urandom(32).hex()

    def _generate_token(self) -> str:
        return secrets.token_urlsafe(32)

    def _constant_time_compare(self, val1: str, val2: str) -> bool:
        return secrets.compare_digest(val1.encode(), val2.encode())

    def create_session(self, data: Dict[str, Any]) -> str:
        session_token = self._generate_token()
        session_key = f"session:{session_token}"
        with self.redis.pipeline() as pipe:
            pipe.hmset(session_key, data)
            pipe.expire(session_key, self.expire_seconds)
            pipe.execute()
        return session_token

    def get_session(self, session_token: str) -> Optional[Dict[str, Any]]:
        session_key = f"session:{session_token}"
        session_data = self.redis.hgetall(session_key)
        if session_data:
            self.redis.expire(session_key, self.expire_seconds)
            return {k.decode(): v.decode() for k, v in session_data.items()}
        return None

    def validate_token(self, provided_token: str, expected_token: str) -> bool:
        return self._constant_time_compare(provided_token, expected_token)

    def delete_session(self, session_token: str) -> None:
        session_key = f"session:{session_token}"
        self.redis.delete(session_key)
