import configparser
import json
import os
from typing import Any, Dict, Union
import yaml

class ConfigReader:
    """Read configuration files in INI, JSON, and YAML formats interchangeably."""

    @staticmethod
    def read_ini(file_path: str) -> Dict[str, Any]:
        """Read an INI configuration file."""
        config = configparser.ConfigParser()
        config.read(file_path)
        return {section: dict(config[section]) for section in config.sections()}

    @staticmethod
    def read_json(file_path: str) -> Dict[str, Any]:
        """Read a JSON configuration file."""
        with open(file_path, 'r') as f:
            return json.load(f)

    @staticmethod
    def read_yaml(file_path: str) -> Dict[str, Any]:
        """Read a YAML configuration file."""
        with open(file_path, 'r') as f:
            return yaml.safe_load(f)

    @staticmethod
    def read_config(file_path: str) -> Dict[str, Any]:
        """Read a configuration file based on its extension."""
        _, ext = os.path.splitext(file_path)
        ext = ext.lower()

        if ext == '.ini':
            return ConfigReader.read_ini(file_path)
        elif ext == '.json':
            return ConfigReader.read_json(file_path)
        elif ext in ('.yaml', '.yml'):
            return ConfigReader.read_yaml(file_path)
        else:
            raise ValueError(f"Unsupported file format: {ext}")
