from abc import ABC, abstractmethod
from typing import Dict, Any

class MarkdownTransformer(ABC):
    @abstractmethod
    def transform(self, markdown: str) -> str:
        pass

class OutputGenerator(ABC):
    @abstractmethod
    def generate(self, content: str, output_path: str) -> None:
        pass

class PluginManager:
    def __init__(self):
        self.transformers: Dict[str, MarkdownTransformer] = {}
        self.generators: Dict[str, OutputGenerator] = {}

    def register_transformer(self, name: str, transformer: MarkdownTransformer) -> None:
        self.transformers[name] = transformer

    def register_generator(self, name: str, generator: OutputGenerator) -> None:
        self.generators[name] = generator

    def get_transformer(self, name: str) -> MarkdownTransformer:
        return self.transformers[name]

    def get_generator(self, name: str) -> OutputGenerator:
        return self.generators[name]

class StaticSiteGenerator:
    def __init__(self, plugin_manager: PluginManager):
        self.plugin_manager = plugin_manager

    def build(self, markdown: str, transformer_name: str, generator_name: str, output_path: str) -> None:
        transformer = self.plugin_manager.get_transformer(transformer_name)
        generator = self.plugin_manager.get_generator(generator_name)

        transformed = transformer.transform(markdown)
        generator.generate(transformed, output_path)
