package main

import (
	"encoding/json"
	"errors"
	"log"
	"net/http"
	"os"
	"time"
)

type Response struct {
	Message string      `json:"message"`
	Data    interface{} `json:"data,omitempty"`
}

type ExternalAPIResponse struct {
	Value string `json:"value"`
}

var logger = log.New(os.Stdout, "SERVICE: ", log.LstdFlags|log.Lshortfile)

func main() {
	http.HandleFunc("/api", handleRequest)
	logger.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	// Validate request
	if r.Method != http.MethodGet {
		logger.Printf("Invalid method: %s", r.Method)
		w.WriteHeader(http.StatusMethodNotAllowed)
		json.NewEncoder(w).Encode(Response{Message: "Method not allowed"})
		return
	}

	// Process request
	data, err := processData()
	if err != nil {
		logger.Printf("Processing error: %v", err)
		w.WriteHeader(http.StatusInternalServerError)
		json.NewEncoder(w).Encode(Response{Message: "Internal server error"})
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(Response{
		Message: "Success",
		Data:    data,
	})
}

func processData() (interface{}, error) {
	// Try primary external API
	data, err := callExternalAPI("https://primary-api.example.com")
	if err != nil {
		logger.Printf("Primary API failed: %v", err)

		// Fallback to secondary API
		data, err = callExternalAPI("https://fallback-api.example.com")
		if err != nil {
			logger.Printf("Fallback API failed: %v", err)
			return nil, errors.New("all external APIs failed")
		}
	}

	// Validate response data
	if data.Value == "" {
		return nil, errors.New("corrupted data from API")
	}

	return data, nil
}

func callExternalAPI(url string) (*ExternalAPIResponse, error) {
	client := &http.Client{Timeout: 5 * time.Second}
	resp, err := client.Get(url)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, errors.New("API returned non-200 status")
	}

	var apiResponse ExternalAPIResponse
	if err := json.NewDecoder(resp.Body).Decode(&apiResponse); err != nil {
		return nil, err
	}

	return &apiResponse, nil
}
