import hashlib
import json
from datetime import datetime
from typing import List, Dict, Optional

class Transaction:
    def __init__(self, user_id: str, amount: float, reason: str, timestamp: datetime):
        self.user_id = user_id
        self.amount = amount
        self.reason = reason
        self.timestamp = timestamp
        self.hash = self._calculate_hash()

    def _calculate_hash(self) -> str:
        data = f"{self.user_id}{self.amount}{self.reason}{self.timestamp.isoformat()}"
        return hashlib.sha256(data.encode()).hexdigest()

    def to_dict(self) -> Dict:
        return {
            "user_id": self.user_id,
            "amount": self.amount,
            "reason": self.reason,
            "timestamp": self.timestamp.isoformat(),
            "hash": self.hash
        }

class Ledger:
    def __init__(self):
        self.chain: List[Transaction] = []

    def add_transaction(self, user_id: str, amount: float, reason: str) -> None:
        transaction = Transaction(user_id, amount, reason, datetime.utcnow())
        self.chain.append(transaction)

    def verify_chain(self) -> bool:
        for i in range(1, len(self.chain)):
            current = self.chain[i]
            previous = self.chain[i - 1]
            if current.hash != current._calculate_hash():
                return False
            if current.timestamp < previous.timestamp:
                return False
        return True

    def query_transactions(self, user_id: Optional[str] = None, start_time: Optional[datetime] = None, end_time: Optional[datetime] = None) -> List[Dict]:
        results = []
        for transaction in self.chain:
            if user_id and transaction.user_id != user_id:
                continue
            if start_time and transaction.timestamp < start_time:
                continue
            if end_time and transaction.timestamp > end_time:
                continue
            results.append(transaction.to_dict())
        return results
