package main

import (
	"context"
	"fmt"
	"log"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

type UserSignupEvent struct {
	UserID    string
	Email     string
	Timestamp time.Time
}

func main() {
	config := Config{
		WorkerCount:  5,
		RateLimitRPS: 10,
		QueueSize:    100,
	}

	consumer := NewConsumer(config)
	consumer.Start()
	defer consumer.Stop()

	// Simulate incoming messages
	for i := 0; i < 20; i++ {
		event := UserSignupEvent{
			UserID:    fmt.Sprintf("user%d", i),
			Email:     fmt.Sprintf("user%d@example.com", i),
			Timestamp: time.Now(),
		}
		consumer.Enqueue(event)
	}

	time.Sleep(2 * time.Second) // Allow time for processing
}

type Config struct {
	WorkerCount  int
	RateLimitRPS int
	QueueSize    int
}

type Consumer struct {
	config      Config
	queue       chan UserSignupEvent
	wg          sync.WaitGroup
	limiter     *rate.Limiter
	ctx         context.Context
	cancel      context.CancelFunc
}

func NewConsumer(config Config) *Consumer {
	ctx, cancel := context.WithCancel(context.Background())
	return &Consumer{
		config:  config,
		queue:   make(chan UserSignupEvent, config.QueueSize),
		limiter: rate.NewLimiter(rate.Limit(config.RateLimitRPS), config.RateLimitRPS),
		ctx:     ctx,
		cancel:  cancel,
	}
}

func (c *Consumer) Start() {
	for i := 0; i < c.config.WorkerCount; i++ {
		c.wg.Add(1)
		go c.worker(i)
	}
}

func (c *Consumer) Stop() {
	c.cancel()
	c.wg.Wait()
	close(c.queue)
}

func (c *Consumer) Enqueue(event UserSignupEvent) {
	select {
	case c.queue <- event:
	default:
		log.Println("Queue full, message dropped")
	}
}

func (c *Consumer) worker(id int) {
	defer c.wg.Done()

	for {
		select {
		case <-c.ctx.Done():
			return
		case event := <-c.queue:
			if err := c.limiter.Wait(c.ctx); err != nil {
				log.Printf("Worker %d: rate limit error: %v", id, err)
				continue
			}
			c.processEvent(event, id)
		}
	}
}

func (c *Consumer) processEvent(event UserSignupEvent, workerID int) {
	// Simulate processing
	log.Printf("Worker %d processing: %+v", workerID, event)
	time.Sleep(100 * time.Millisecond)
}
