use clap::{Parser, Subcommand, ValueEnum};
use std::fmt;

#[derive(Debug, Parser)]
#[command(name = "taskmgr")]
#[command(version, about, long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Debug, Subcommand)]
enum Commands {
    /// Add a new task
    Add {
        /// Task description
        description: String,
        /// Task priority (low, medium, high)
        #[arg(value_enum, default_value_t = Priority::Medium)]
        priority: Priority,
    },
    /// List all tasks
    List,
    /// Complete a task by ID
    Complete {
        /// Task ID
        id: usize,
    },
    /// Delete a task by ID
    Delete {
        /// Task ID
        id: usize,
    },
}

#[derive(Debug, Clone, ValueEnum)]
enum Priority {
    Low,
    Medium,
    High,
}

impl fmt::Display for Priority {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            Priority::Low => write!(f, "low"),
            Priority::Medium => write!(f, "medium"),
            Priority::High => write!(f, "high"),
        }
    }
}

struct Task {
    id: usize,
    description: String,
    priority: Priority,
    completed: bool,
}

struct TaskManager {
    tasks: Vec<Task>,
    next_id: usize,
}

impl TaskManager {
    fn new() -> Self {
        TaskManager {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    fn add_task(&mut self, description: String, priority: Priority) -> usize {
        let id = self.next_id;
        self.tasks.push(Task {
            id,
            description,
            priority,
            completed: false,
        });
        self.next_id += 1;
        id
    }

    fn list_tasks(&self) {
        if self.tasks.is_empty() {
            println!("No tasks found.");
            return;
        }

        for task in &self.tasks {
            let status = if task.completed { "✓" } else { " " };
            println!("[{}] {} {} ({})", task.id, status, task.description, task.priority);
        }
    }

    fn complete_task(&mut self, id: usize) -> Result<(), String> {
        match self.tasks.iter_mut().find(|t| t.id == id) {
            Some(task) => {
                task.completed = true;
                Ok(())
            }
            None => Err(format!("Task with ID {} not found", id)),
        }
    }

    fn delete_task(&mut self, id: usize) -> Result<(), String> {
        if let Some(pos) = self.tasks.iter().position(|t| t.id == id) {
            self.tasks.remove(pos);
            Ok(())
        } else {
            Err(format!("Task with ID {} not found", id))
        }
    }
}

fn main() {
    let cli = Cli::parse();
    let mut manager = TaskManager::new();

    match cli.command {
        Commands::Add { description, priority } => {
            let id = manager.add_task(description, priority);
            println!("Added task with ID {}", id);
        }
        Commands::List => {
            manager.list_tasks();
        }
        Commands::Complete { id } => {
            match manager.complete_task(id) {
                Ok(_) => println!("Task {} marked as complete", id),
                Err(e) => eprintln!("Error: {}", e),
            }
        }
        Commands::Delete { id } => {
            match manager.delete_task(id) {
                Ok(_) => println!("Task {} deleted", id),
                Err(e) => eprintln!("Error: {}", e),
            }
        }
    }
}
