import express, { Request, Response, NextFunction } from 'express';
import { escape } from 'sqlstring';
import xss from 'xss';

const app = express();

// Middleware to sanitize user input
const sanitizeInput = (req: Request, res: Response, next: NextFunction) => {
    if (req.body) {
        for (const key in req.body) {
            if (typeof req.body[key] === 'string') {
                req.body[key] = xss(req.body[key]); // Prevent XSS
                req.body[key] = escape(req.body[key]); // Prevent SQL injection
            }
        }
    }
    if (req.query) {
        for (const key in req.query) {
            if (typeof req.query[key] === 'string') {
                req.query[key] = xss(req.query[key] as string); // Prevent XSS
                req.query[key] = escape(req.query[key] as string); // Prevent SQL injection
            }
        }
    }
    next();
};

app.use(express.json());
app.use(sanitizeInput);

// Test route
app.post('/test', (req: Request, res: Response) => {
    res.json({
        body: req.body,
        query: req.query
    });
});

app.listen(3000, () => {
    console.log('Server running on port 3000');
});
