import requests
import hashlib
import argon2
from zxcvbn import zxcvbn

class PasswordPolicyValidator:
    def __init__(self, min_entropy=3, min_length=8):
        self.min_entropy = min_entropy
        self.min_length = min_length
        self.argon2_hasher = argon2.PasswordHasher(
            time_cost=3,
            memory_cost=65536,
            parallelism=4,
            hash_len=32,
            salt_len=16
        )

    def _check_hibp(self, password):
        sha1_hash = hashlib.sha1(password.encode('utf-8')).hexdigest().upper()
        prefix, suffix = sha1_hash[:5], sha1_hash[5:]
        url = f"https://api.pwnedpasswords.com/range/{prefix}"

        try:
            response = requests.get(url)
            if response.status_code == 200:
                hashes = (line.split(':') for line in response.text.splitlines())
                for h, count in hashes:
                    if h == suffix:
                        return int(count)
            return 0
        except requests.RequestException:
            return -1

    def validate(self, password):
        if len(password) < self.min_length:
            return False, "Password too short"

        entropy_result = zxcvbn(password)
        if entropy_result['score'] < self.min_entropy:
            return False, "Password too weak"

        breach_count = self._check_hibp(password)
        if breach_count == -1:
            return False, "Could not check password against breach database"
        elif breach_count > 0:
            return False, "Password found in breaches"

        return True, "Password meets policy requirements"

    def hash_password(self, password):
        return self.argon2_hasher.hash(password)

    def verify_password(self, hashed_password, plain_password):
        try:
            return self.argon2_hasher.verify(hashed_password, plain_password)
        except (argon2.exceptions.VerifyMismatchError, argon2.exceptions.InvalidHashError):
            return False
