# --------------------------
# Abstract Base Classes
# --------------------------

class BaseExtractor(ABC):
    """Abstract base class for data extraction operations."""

    @abstractmethod
    def extract(self) -> List[Dict[str, Any]]:
        """Extract raw data from a source.

        Returns:
            List of dictionaries representing raw records.
        """
        pass

class BaseTransformer(ABC):
    """Abstract base class for data transformation operations."""

    @abstractmethod
    def transform(self, data: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        """Transform raw data into processed format.

        Args:
            data: Raw records to transform.

        Returns:
            Transformed records.
        """
        pass

class BaseLoader(ABC):
    """Abstract base class for data loading operations."""

    @abstractmethod
    def load(self, data: List[Dict[str, Any]]) -> bool:
        """Load processed data to a destination.

        Args:
            data: Processed records to load.

        Returns:
            True if load succeeded.
        """
        pass

# --------------------------
# Pipeline Implementation
# --------------------------

@dataclass
class ETLPipeline:
    """Modular ETL pipeline composed of extractor, transformer, and loader."""
    extractor: BaseExtractor
    transformer: BaseTransformer
    loader: BaseLoader

    def run(self) -> bool:
        """Execute full ETL pipeline.

        Returns:
            True if pipeline completed successfully.
        """
        raw_data = self.extractor.extract()
        processed_data = self.transformer.transform(raw_data)
        return self.loader.load(processed_data)

