import hashlib
import random
import time
from typing import Dict, List, Optional, Tuple

class VirtualNode:
    def __init__(self, node_id: str, virtual_id: int):
        self.node_id = node_id
        self.virtual_id = virtual_id
        self.hash = self._compute_hash()

    def _compute_hash(self) -> int:
        key = f"{self.node_id}-{self.virtual_id}".encode()
        return int(hashlib.md5(key).hexdigest(), 16)

class ShardedKVStore:
    def __init__(self, virtual_nodes_per_node: int = 3):
        self.virtual_nodes_per_node = virtual_nodes_per_node
        self.ring: Dict[int, VirtualNode] = {}  # hash -> VirtualNode
        self.data: Dict[str, str] = {}  # key -> value
        self.nodes: Dict[str, List[VirtualNode]] = {}  # node_id -> [VirtualNode]
        self.gossip_members: Dict[str, int] = {}  # node_id -> timestamp

    def add_node(self, node_id: str) -> None:
        virtual_nodes = [
            VirtualNode(node_id, i) for i in range(self.virtual_nodes_per_node)
        ]
        self.nodes[node_id] = virtual_nodes
        for vnode in virtual_nodes:
            self.ring[vnode.hash] = vnode
        self.gossip_members[node_id] = int(time.time())

    def remove_node(self, node_id: str) -> None:
        for vnode in self.nodes.get(node_id, []):
            self.ring.pop(vnode.hash, None)
        self.nodes.pop(node_id, None)
        self.gossip_members.pop(node_id, None)

    def get_node(self, key: str) -> Optional[str]:
        if not self.ring:
            return None
        key_hash = self._hash_key(key)
        sorted_hashes = sorted(self.ring.keys())
        for hash_val in sorted_hashes:
            if key_hash <= hash_val:
                return self.ring[hash_val].node_id
        return self.ring[sorted_hashes[0]].node_id

    def put(self, key: str, value: str) -> None:
        node_id = self.get_node(key)
        if node_id:
            self.data[key] = value

    def get(self, key: str) -> Optional[str]:
        return self.data.get(key)

    def _hash_key(self, key: str) -> int:
        return int(hashlib.md5(key.encode()).hexdigest(), 16)

    def gossip(self, other_nodes: List[str]) -> None:
        current_time = int(time.time())
        # Update our membership with other nodes' info
        for node in other_nodes:
            if node in self.gossip_members:
                self.gossip_members[node] = current_time
        # Remove stale nodes (e.g., haven't been seen in 30s)
        stale_nodes = [
            node
            for node, ts in self.gossip_members.items()
            if current_time - ts > 30 and node not in self.nodes
        ]
        for node in stale_nodes:
            self.gossip_members.pop(node)

    def redistribute_data(self) -> None:
        # This would be called periodically or when nodes join/leave
        # For simplicity, we're just clearing the data here
        # In a real implementation, you'd redistribute to new nodes
        self.data = {}
