from abc import ABC, abstractmethod
from typing import BinaryIO, Optional
import boto3
from google.cloud import storage
import os
import vcr
from unittest import TestCase

class CloudStorageAdapter(ABC):
    @abstractmethod
    def upload(self, bucket: str, key: str, data: BinaryIO) -> None:
        pass

    @abstractmethod
    def download(self, bucket: str, key: str) -> BinaryIO:
        pass

class S3Adapter(CloudStorageAdapter):
    def __init__(self, client=None):
        self.client = client or boto3.client('s3')

    def upload(self, bucket: str, key: str, data: BinaryIO) -> None:
        self.client.upload_fileobj(data, bucket, key)

    def download(self, bucket: str, key: str) -> BinaryIO:
        response = self.client.get_object(Bucket=bucket, Key=key)
        return response['Body']

class GCSAdapter(CloudStorageAdapter):
    def __init__(self, client=None):
        self.client = client or storage.Client()

    def upload(self, bucket: str, key: str, data: BinaryIO) -> None:
        bucket = self.client.bucket(bucket)
        blob = bucket.blob(key)
        blob.upload_from_file(data)

    def download(self, bucket: str, key: str) -> BinaryIO:
        bucket = self.client.bucket(bucket)
        blob = bucket.blob(key)
        return blob.open('rb')

class LocalStorageAdapter(CloudStorageAdapter):
    def __init__(self, base_path: str = './storage'):
        self.base_path = base_path
        os.makedirs(base_path, exist_ok=True)

    def upload(self, bucket: str, key: str, data: BinaryIO) -> None:
        path = os.path.join(self.base_path, bucket, key)
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, 'wb') as f:
            f.write(data.read())

    def download(self, bucket: str, key: str) -> BinaryIO:
        path = os.path.join(self.base_path, bucket, key)
        return open(path, 'rb')

class StorageService:
    def __init__(self, adapter: Optional[CloudStorageAdapter] = None):
        self.adapter = adapter or LocalStorageAdapter()

    def upload(self, bucket: str, key: str, data: BinaryIO) -> None:
        self.adapter.upload(bucket, key, data)

    def download(self, bucket: str, key: str) -> BinaryIO:
        return self.adapter.download(bucket, key)

class StorageTests(TestCase):
    def setUp(self):
        self.vcr = vcr.VCR(
            cassette_library_dir='fixtures/cassettes',
            record_mode='once',
            match_on=['method', 'scheme', 'host', 'path', 'query']
        )

    def test_s3_upload_download(self):
        with self.vcr.use_cassette('s3_operations.yaml'):
            s3 = StorageService(S3Adapter())
            test_data = b'test data'
            with open('test.txt', 'wb') as f:
                f.write(test_data)
            with open('test.txt', 'rb') as f:
                s3.upload('test-bucket', 'test.txt', f)
            downloaded = s3.download('test-bucket', 'test.txt')
            assert downloaded.read() == test_data

    def test_gcs_upload_download(self):
        with self.vcr.use_cassette('gcs_operations.yaml'):
            gcs = StorageService(GCSAdapter())
            test_data = b'test data'
            with open('test.txt', 'wb') as f:
                f.write(test_data)
            with open('test.txt', 'rb') as f:
                gcs.upload('test-bucket', 'test.txt', f)
            downloaded = gcs.download('test-bucket', 'test.txt')
            assert downloaded.read() == test_data
