import cmd
import readline
import shlex
from typing import List, Dict, Any, Optional
from enum import Enum

class ConfigFieldType(Enum):
    STRING = "string"
    INTEGER = "integer"
    BOOLEAN = "boolean"
    SELECT = "select"

class ConfigField:
    def __init__(self, name: str, field_type: ConfigFieldType, description: str, 
                 options: Optional[List[str]] = None, default: Any = None):
        self.name = name
        self.type = field_type
        self.description = description
        self.options = options
        self.default = default
        self.value = default

    def validate(self, value: str) -> bool:
        try:
            if self.type == ConfigFieldType.STRING:
                return True
            elif self.type == ConfigFieldType.INTEGER:
                int(value)
                return True
            elif self.type == ConfigFieldType.BOOLEAN:
                return value.lower() in ['true', 'false', 'yes', 'no', '1', '0']
            elif self.type == ConfigFieldType.SELECT:
                return value in self.options
        except ValueError:
            return False
        return False

    def set_value(self, value: str) -> bool:
        if not self.validate(value):
            return False

        if self.type == ConfigFieldType.BOOLEAN:
            self.value = value.lower() in ['true', 'yes', '1']
        elif self.type == ConfigFieldType.INTEGER:
            self.value = int(value)
        else:
            self.value = value
        return True

class ConfigWizard(cmd.Cmd):
    prompt = "(config) "
    intro = "Server Configuration Wizard. Type 'help' for commands."

    def __init__(self):
        super().__init__()
        self.fields: Dict[str, ConfigField] = {
            "hostname": ConfigField("hostname", ConfigFieldType.STRING, "Server hostname", default="localhost"),
            "port": ConfigField("port", ConfigFieldType.INTEGER, "Server port", default=8080),
            "ssl": ConfigField("ssl", ConfigFieldType.BOOLEAN, "Enable SSL", default=False),
            "environment": ConfigField("environment", ConfigFieldType.SELECT, "Server environment", 
                                      options=["development", "staging", "production"], default="development")
        }
        self.history: List[Dict[str, Any]] = []
        self.history_index = -1

    def preloop(self):
        self.save_state()

    def save_state(self):
        state = {name: field.value for name, field in self.fields.items()}
        self.history = self.history[:self.history_index + 1]
        self.history.append(state)
        self.history_index = len(self.history) - 1

    def undo(self):
        if self.history_index > 0:
            self.history_index -= 1
            self.load_state()

    def redo(self):
        if self.history_index < len(self.history) - 1:
            self.history_index += 1
            self.load_state()

    def load_state(self):
        state = self.history[self.history_index]
        for name, value in state.items():
            self.fields[name].value = value

    def complete_set(self, text: str, line: str, begidx: int, endidx: int) -> List[str]:
        return [name for name in self.fields.keys() if name.startswith(text)]

    def do_set(self, arg: str):
        """Set a configuration value: set <field> <value>"""
        args = shlex.split(arg)
        if len(args) != 2:
            print("Usage: set <field> <value>")
            return

        field_name, value = args
        if field_name not in self.fields:
            print(f"Invalid field: {field_name}")
            return

        field = self.fields[field_name]
        if not field.set_value(value):
            print(f"Invalid value for {field_name}. Expected {field.type.value}")
            if field.type == ConfigFieldType.SELECT:
                print(f"Options: {', '.join(field.options)}")
            return

        self.save_state()
        print(f"Set {field_name} = {field.value}")

    def do_get(self, arg: str):
        """Get configuration value(s): get [<field>]"""
        if not arg:
            for name, field in self.fields.items():
                print(f"{name}: {field.value} ({field.description})")
        else:
            field_name = arg.strip()
            if field_name not in self.fields:
                print(f"Invalid field: {field_name}")
                return
            field = self.fields[field_name]
            print(f"{field_name}: {field.value} ({field.description})")

    def do_preview(self, _):
        """Show rich-text preview of current configuration"""
        print("\n=== Current Configuration ===")
        for name, field in self.fields.items():
            print(f"\033[1m{name}:\033[0m {field.value}")
        print("============================\n")

    def do_undo(self, _):
        """Undo last configuration change"""
        self.undo()
        print("Undo complete. Current state:")
        self.do_get("")

    def do_redo(self, _):
        """Redo last undone change"""
        self.redo()
        print("Redo complete. Current state:")
        self.do_get("")

    def do_help(self, arg: str):
        """Show help for commands or specific field"""
        if arg and arg in self.fields:
            field = self.fields[arg]
            print(f"\nHelp for {arg}:")
            print(f"  Type: {field.type.value}")
            print(f"  Description: {field.description}")
            if field.options:
                print(f"  Options: {', '.join(field.options)}")
            print(f"  Current value: {field.value}\n")
        else:
            super().do_help(arg)

    def do_exit(self, _):
        """Exit the configuration wizard"""
        print("Configuration complete. Exiting.")
        return True

    do_EOF = do_exit

if __name__ == "__main__":
    ConfigWizard().cmdloop()
