from abc import ABC, abstractmethod
from typing import Dict, Any, Callable
import weakref

# Event Bus
class EventBus:
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._subscribers = weakref.WeakValueDictionary()
        return cls._instance

    def subscribe(self, event_type: str, subscriber: Any):
        if event_type not in self._subscribers:
            self._subscribers[event_type] = []
        self._subscribers[event_type].append(subscriber)

    def publish(self, event_type: str, data: Any = None):
        for subscriber in self._subscribers.get(event_type, []):
            subscriber.handle_event(event_type, data)

# Abstract Widget Factory
class WidgetFactory(ABC):
    @abstractmethod
    def create_button(self, text: str, on_click: Callable) -> Any:
        pass

    @abstractmethod
    def create_label(self, text: str) -> Any:
        pass

# Strategy Interface
class RendererStrategy(ABC):
    @abstractmethod
    def render(self, factory: WidgetFactory) -> Any:
        pass

# Platform-Specific Implementations
class QtFactory(WidgetFactory):
    def create_button(self, text: str, on_click: Callable) -> Any:
        from PyQt5.QtWidgets import QPushButton
        btn = QPushButton(text)
        btn.clicked.connect(on_click)
        return btn

    def create_label(self, text: str) -> Any:
        from PyQt5.QtWidgets import QLabel
        return QLabel(text)

class WxPythonFactory(WidgetFactory):
    def create_button(self, text: str, on_click: Callable) -> Any:
        import wx
        btn = wx.Button(None, label=text)
        btn.Bind(wx.EVT_BUTTON, lambda e: on_click())
        return btn

    def create_label(self, text: str) -> Any:
        import wx
        return wx.StaticText(None, label=text)

class TextualFactory(WidgetFactory):
    def create_button(self, text: str, on_click: Callable) -> Any:
        from textual.widgets import Button
        return Button(text, on_click)

    def create_label(self, text: str) -> Any:
        from textual.widgets import Static
        return Static(text)

# Concrete Strategies
class QtRenderer(RendererStrategy):
    def render(self, factory: WidgetFactory) -> Any:
        from PyQt5.QtWidgets import QApplication, QVBoxLayout, QWidget
        app = QApplication([])
        window = QWidget()
        layout = QVBoxLayout()

        button = factory.create_button("Click me", lambda: print("Qt clicked"))
        label = factory.create_label("Qt Label")

        layout.addWidget(label)
        layout.addWidget(button)
        window.setLayout(layout)
        window.show()
        app.exec_()

class WxPythonRenderer(RendererStrategy):
    def render(self, factory: WidgetFactory) -> Any:
        import wx
        app = wx.App()
        frame = wx.Frame(None, title="WxPython")
        panel = wx.Panel(frame)
        sizer = wx.BoxSizer(wx.VERTICAL)

        button = factory.create_button("Click me", lambda: print("Wx clicked"))
        label = factory.create_label("Wx Label")

        sizer.Add(label, 0, wx.ALL, 5)
        sizer.Add(button, 0, wx.ALL, 5)
        panel.SetSizer(sizer)
        frame.Show()
        app.MainLoop()

class TextualRenderer(RendererStrategy):
    def render(self, factory: WidgetFactory) -> Any:
        from textual.app import App, ComposeResult
        from textual.containers import Vertical

        class TextualApp(App):
            def compose(self) -> ComposeResult:
                yield Vertical(
                    factory.create_label("Textual Label"),
                    factory.create_button("Click me", lambda: print("Textual clicked"))
                )

        TextualApp().run()

# Client Code
def main(renderer: RendererStrategy):
    event_bus = EventBus()
    factory = None

    if isinstance(renderer, QtRenderer):
        factory = QtFactory()
    elif isinstance(renderer, WxPythonRenderer):
        factory = WxPythonFactory()
    elif isinstance(renderer, TextualRenderer):
        factory = TextualFactory()

    renderer.render(factory)

# Usage:
# main(QtRenderer())
# main(WxPythonRenderer())
# main(TextualRenderer())
