    def __init__(self, access_token: str):
        self.access_token = access_token

    def geocode(self, address: str) -> Optional[GeocodingResult]:
        # Actual implementation would call Mapbox API
        pass

class CachedGeocodingService:
    def __init__(self, provider: GeocodingProvider, cache_file: str = "geocoding_cache.json"):
        self.provider = provider
        self.cache_file = cache_file
        self._load_cache()

    def _load_cache(self):
        if os.path.exists(self.cache_file):
            with open(self.cache_file, "r") as f:
                self.cache = json.load(f)
        else:
            self.cache = {}

    def _save_cache(self):
        with open(self.cache_file, "w") as f:
            json.dump(self.cache, f)

    def geocode(self, address: str) -> Optional[GeocodingResult]:
        if address in self.cache:
            cached = self.cache[address]
            return GeocodingResult(**cached)

        result = self.provider.geocode(address)
        if result:
            self.cache[address] = {
                "latitude": result.latitude,
                "longitude": result.longitude,
                "address": result.address
            }
            self._save_cache()

        return result

