const WebSocket = require('ws');
const Redis = require('ioredis');
const ConsistentHashing = require('consistent-hashing');

// Initialize Redis clients
const pubClient = new Redis();
const subClient = new Redis();

// Consistent hashing ring
const ring = new ConsistentHashing(['node1', 'node2', 'node3']); // Initial nodes

// WebSocket server
const wss = new WebSocket.Server({ port: 8080 });

// Track connected clients
const clients = new Map();

wss.on('connection', (ws, req) => {
  const clientId = req.headers['sec-websocket-key'];
  const shardKey = req.url.split('=')[1]; // Extract shard key from URL
  const node = ring.getNode(shardKey);

  if (node !== process.env.NODE_ID) {
    // Redirect to correct node
    ws.close(1008, `Redirect to node: ${node}`);
    return;
  }

  clients.set(clientId, ws);

  // Subscribe to Redis channel for cross-node messages
  subClient.subscribe(`node:${process.env.NODE_ID}`);

  ws.on('message', (message) => {
    // Broadcast to other nodes via Redis PUB/SUB
    pubClient.publish(`node:${node}`, message);
  });

  ws.on('close', () => {
    clients.delete(clientId);
    if (clients.size === 0) {
      subClient.unsubscribe(`node:${process.env.NODE_ID}`);
    }
  });
});

// Handle Redis messages
subClient.on('message', (channel, message) => {
  clients.forEach((client) => {
    if (client.readyState === WebSocket.OPEN) {
      client.send(message);
    }
  });
});

// Node membership events
process.on('SIGUSR2', () => {
  // Handle node join
  ring.addNode(`node${ring.nodes.length + 1}`);
  rebalanceConnections();
});

process.on('SIGTERM', () => {
  // Handle node leave
  ring.removeNode(process.env.NODE_ID);
  migrateConnections();
  process.exit(0);
});

