import click
import sqlparse
from pygments import highlight
from pygments.lexers import SqlLexer
from pygments.formatters import TerminalFormatter
from rich.table import Table
from rich.progress import Progress
from rich.console import Console
from prompt_toolkit import prompt
from prompt_toolkit.completion import WordCompleter
from prompt_toolkit.history import FileHistory
from prompt_toolkit.lexers import PygmentsLexer
from typing import List, Dict, Optional

console = Console()
migration_history: List[str] = []
undo_stack: List[str] = []

def validate_query(query: str) -> bool:
    try:
        sqlparse.parse(query)
        return True
    except:
        return False

def syntax_highlight(query: str) -> str:
    return highlight(query, SqlLexer(), TerminalFormatter())

def dry_run_preview(query: str) -> Table:
    table = Table(title="Dry Run Preview")
    table.add_column("Operation", style="cyan")
    table.add_column("Affected Rows", style="magenta")
    table.add_row("SELECT", "100")
    return table

def show_progress():
    with Progress() as progress:
        task = progress.add_task("[cyan]Migrating...", total=100)
        while not progress.finished:
            progress.update(task, advance=1)

@click.group()
def cli():
    pass

@cli.command()
def interactive():
    sql_completer = WordCompleter(["SELECT", "INSERT", "UPDATE", "DELETE", "CREATE", "ALTER", "DROP"], ignore_case=True)

    while True:
        try:
            query = prompt(
                "migration> ",
                lexer=PygmentsLexer(SqlLexer),
                completer=sql_completer,
                history=FileHistory(".migration_history")
            )

            if query.lower() in ("exit", "quit"):
                break

            if not validate_query(query):
                console.print("[red]Invalid SQL syntax[/red]")
                continue

            console.print(syntax_highlight(query))

            if click.confirm("Dry run?"):
                console.print(dry_run_preview(query))

            if click.confirm("Execute?"):
                migration_history.append(query)
                show_progress()
                console.print("[green]Migration successful[/green]")

        except KeyboardInterrupt:
            continue
        except EOFError:
            break

@cli.command()
def undo():
    if migration_history:
        last_migration = migration_history.pop()
        undo_stack.append(last_migration)
        console.print(f"[yellow]Undo: {last_migration}[/yellow]")
    else:
        console.print("[red]Nothing to undo[/red]")

@cli.command()
def redo():
    if undo_stack:
        last_undone = undo_stack.pop()
        migration_history.append(last_undone)
        console.print(f"[green]Redo: {last_undone}[/green]")
    else:
        console.print("[red]Nothing to redo[/red]")

if __name__ == "__main__":
    cli()
