import { useEffect, useState } from 'react';
import { generateRandomString, sha256 } from './cryptoUtils';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authServer = 'https://auth.server.com';

const AuthComponent = () => {
  const [csrfToken, setCsrfToken] = useState('');
  const [codeVerifier, setCodeVerifier] = useState('');

  useEffect(() => {
    // Generate CSRF token and PKCE code verifier
    setCsrfToken(generateRandomString());
    const verifier = generateRandomString(64);
    setCodeVerifier(verifier);
    sessionStorage.setItem('code_verifier', verifier);
    sessionStorage.setItem('csrf_token', csrfToken);
  }, []);

  const login = async () => {
    const codeChallenge = await sha256(codeVerifier);
    const authUrl = `${authServer}/authorize?response_type=code` +
      `&client_id=${clientId}` +
      `&redirect_uri=${redirectUri}` +
      `&code_challenge=${codeChallenge}` +
      `&code_challenge_method=S256` +
      `&state=${csrfToken}` +
      `&scope=openid%20profile`;

    window.location.href = authUrl;
  };

  const handleCallback = async () => {
    const params = new URLSearchParams(window.location.search);
    const code = params.get('code');
    const state = params.get('state');

    if (state !== sessionStorage.getItem('csrf_token')) {
      throw new Error('CSRF token mismatch');
    }

    const tokenResponse = await fetch(`${authServer}/token`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        client_id: clientId,
        redirect_uri: redirectUri,
        code,
        code_verifier: sessionStorage.getItem('code_verifier'),
      }),
      credentials: 'include'
    });

    const tokens = await tokenResponse.json();
    startTokenRotation(tokens);
  };

  const startTokenRotation = (tokens) => {
    const rotateInterval = setInterval(async () => {
      const response = await fetch(`${authServer}/token`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          client_id: clientId,
          refresh_token: tokens.refresh_token,
        }),
        credentials: 'include'
      });
      tokens = await response.json();
    }, (tokens.expires_in - 60) * 1000);
  };

  return <button onClick={login}>Login</button>;
};

// Backend (Node.js/Express example)
