from abc import ABC, abstractmethod
from typing import Generic, TypeVar, Callable, List
from dataclasses import dataclass
import graphviz

T = TypeVar('T')

class Specification(ABC, Generic[T]):
    @abstractmethod
    def is_satisfied_by(self, candidate: T) -> bool:
        pass

    def __and__(self, other: 'Specification[T]') -> 'Specification[T]':
        return AndSpecification(self, other)

    def __or__(self, other: 'Specification[T]') -> 'Specification[T]':
        return OrSpecification(self, other)

    def __invert__(self) -> 'Specification[T]':
        return NotSpecification(self)

    def to_graphviz(self) -> graphviz.Digraph:
        dot = graphviz.Digraph()
        self._add_to_graphviz(dot)
        return dot

    @abstractmethod
    def _add_to_graphviz(self, dot: graphviz.Digraph) -> str:
        pass

@dataclass(frozen=True)
class AndSpecification(Specification[T]):
    left: Specification[T]
    right: Specification[T]

    def is_satisfied_by(self, candidate: T) -> bool:
        return self.left.is_satisfied_by(candidate) and self.right.is_satisfied_by(candidate)

    def _add_to_graphviz(self, dot: graphviz.Digraph) -> str:
        node_id = str(id(self))
        left_id = self.left._add_to_graphviz(dot)
        right_id = self.right._add_to_graphviz(dot)
        dot.node(node_id, label="AND")
        dot.edge(node_id, left_id)
        dot.edge(node_id, right_id)
        return node_id

@dataclass(frozen=True)
class OrSpecification(Specification[T]):
    left: Specification[T]
    right: Specification[T]

    def is_satisfied_by(self, candidate: T) -> bool:
        return self.left.is_satisfied_by(candidate) or self.right.is_satisfied_by(candidate)

    def _add_to_graphviz(self, dot: graphviz.Digraph) -> str:
        node_id = str(id(self))
        left_id = self.left._add_to_graphviz(dot)
        right_id = self.right._add_to_graphviz(dot)
        dot.node(node_id, label="OR")
        dot.edge(node_id, left_id)
        dot.edge(node_id, right_id)
        return node_id

@dataclass(frozen=True)
class NotSpecification(Specification[T]):
    spec: Specification[T]

    def is_satisfied_by(self, candidate: T) -> bool:
        return not self.spec.is_satisfied_by(candidate)

    def _add_to_graphviz(self, dot: graphviz.Digraph) -> str:
        node_id = str(id(self))
        spec_id = self.spec._add_to_graphviz(dot)
        dot.node(node_id, label="NOT")
        dot.edge(node_id, spec_id)
        return node_id

@dataclass(frozen=True)
class ConditionSpecification(Specification[T]):
    condition: Callable[[T], bool]
    name: str

    def is_satisfied_by(self, candidate: T) -> bool:
        return self.condition(candidate)

    def _add_to_graphviz(self, dot: graphviz.Digraph) -> str:
        node_id = str(id(self))
        dot.node(node_id, label=self.name)
        return node_id

class RuleEngine:
    @staticmethod
    def create_rule(name: str, condition: Callable[[T], bool]) -> Specification[T]:
        return ConditionSpecification(condition, name)

    @staticmethod
    def evaluate(candidate: T, *specs: Specification[T]) -> bool:
        return all(spec.is_satisfied_by(candidate) for spec in specs)

    @staticmethod
    def visualize(spec: Specification[T]) -> graphviz.Digraph:
        return spec.to_graphviz()
