package main

import (
	"bufio"
	"compress/gzip"
	"fmt"
	"io"
	"log"
	"os"
	"runtime"
	"sync"
	"testing"
	"time"
)

type LogEntry struct {
	IP        string
	Timestamp string
	Method    string
	Path      string
	Protocol  string
	Status    int
	Size      int
}

var logPool = sync.Pool{
	New: func() interface{} {
		return new(LogEntry)
	},
}

func parseLogLine(line string) *LogEntry {
	entry := logPool.Get().(*LogEntry)
	// Simplified parsing - adjust according to your log format
	fmt.Sscanf(line, "%s %s %s %s %s %d %d",
		&entry.IP,
		&entry.Timestamp,
		&entry.Method,
		&entry.Path,
		&entry.Protocol,
		&entry.Status,
		&entry.Size,
	)
	return entry
}

func processFile(path string, workers int) error {
	file, err := os.Open(path)
	if err != nil {
		return err
	}
	defer file.Close()

	gz, err := gzip.NewReader(file)
	if err != nil {
		return err
	}
	defer gz.Close()

	lines := make(chan string, workers*100)
	done := make(chan struct{})
	wg := sync.WaitGroup{}

	// Start workers
	for i := 0; i < workers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for line := range lines {
				entry := parseLogLine(line)
				// Process entry here
				_ = entry
				logPool.Put(entry)
			}
		}()
	}

	// Read lines
	scanner := bufio.NewScanner(gz)
	for scanner.Scan() {
		lines <- scanner.Text()
	}
	close(lines)

	if err := scanner.Err(); err != nil {
		return err
	}

	wg.Wait()
	close(done)
	return nil
}

