const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());
app.use(helmet());

// Key rotation setup
const keyPairs = [
  { id: 1, privateKey: crypto.generateKeyPairSync('rsa', { modulusLength: 2048 }).privateKey.export({ type: 'pkcs1', format: 'pem' }) },
  { id: 2, privateKey: crypto.generateKeyPairSync('rsa', { modulusLength: 2048 }).privateKey.export({ type: 'pkcs1', format: 'pem' }) }
];
let currentKeyId = 1;

// Token store for refresh tokens and invalidated tokens
const tokenStore = {
  refreshTokens: new Set(),
  invalidatedTokens: new Set()
};

// Rate limiting for auth endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100
});

// Generate tokens
function generateTokens(userId) {
  const accessToken = jwt.sign(
    { userId, jti: uuidv4() },
    keyPairs.find(k => k.id === currentKeyId).privateKey,
    { algorithm: 'RS256', expiresIn: '15m' }
  );

  const refreshToken = uuidv4();
  tokenStore.refreshTokens.add(refreshToken);

  return { accessToken, refreshToken };
}

// Key rotation middleware
function rotateKeys() {
  currentKeyId = currentKeyId === 1 ? 2 : 1;
  setTimeout(rotateKeys, 7 * 24 * 60 * 60 * 1000); // Rotate weekly
}

// Auth middleware
function authenticate(req, res, next) {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.sendStatus(401);

  // Check if token was invalidated
  if (tokenStore.invalidatedTokens.has(token)) return res.sendStatus(401);

  try {
    // Try both keys for verification
    let decoded;
    for (const key of keyPairs) {
      try {
        decoded = jwt.verify(token, key.privateKey, { algorithms: ['RS256'] });
        break;
      } catch {}
    }

    if (!decoded) return res.sendStatus(401);

    // CSRF protection
    if (req.method !== 'GET' && req.headers['x-csrf-token'] !== decoded.jti) {
      return res.sendStatus(403);
    }

    req.user = decoded;
    next();
  } catch (err) {
    res.sendStatus(401);
  }
}

// Routes
app.post('/login', authLimiter, (req, res) => {
  const { username, password } = req.body;
  // Validate credentials here
  const userId = 'user123'; // Replace with actual user ID
  const tokens = generateTokens(userId);
  res.json(tokens);
});

app.post('/refresh', authLimiter, (req, res) => {
  const { refreshToken } = req.body;
  if (!tokenStore.refreshTokens.has(refreshToken)) return res.sendStatus(401);

  tokenStore.refreshTokens.delete(refreshToken);
  const userId = 'user123'; // Get from refresh token if stored
  const tokens = generateTokens(userId);
  res.json(tokens);
});

app.post('/logout', authenticate, (req, res) => {
  const token = req.headers['authorization'].split(' ')[1];
  tokenStore.invalidatedTokens.add(token);
  res.sendStatus(200);
});

// Protected route example
app.get('/protected', authenticate, (req, res) => {
  res.json({ message: 'Protected data' });
});

// Start key rotation
rotateKeys();

app.listen(3000, () => console.log('Server running on port 3000'));
