import org.apache.kafka.clients.consumer.Consumer;
import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.Producer;
import org.apache.kafka.clients.producer.ProducerConfig;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.serialization.StringDeserializer;
import org.apache.kafka.common.serialization.StringSerializer;
import org.junit.jupiter.api.Test;
import org.testcontainers.containers.KafkaContainer;
import org.testcontainers.junit.jupiter.Container;
import org.testcontainers.junit.jupiter.Testcontainers;
import org.testcontainers.utility.DockerImageName;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.UUID;

public interface KafkaProducerInterface {
    void send(String topic, String message);
}

public interface KafkaConsumerInterface {
    void subscribe(String topic);
    ConsumerRecords<String, String> poll();
}

public class KafkaEventProcessor {
    private final KafkaProducerInterface producer;
    private final KafkaConsumerInterface consumer;

    public KafkaEventProcessor(KafkaProducerInterface producer, KafkaConsumerInterface consumer) {
        this.producer = producer;
        this.consumer = consumer;
    }

    public void processEvent(String topic, String message) {
        producer.send(topic, message);
    }

    public ConsumerRecords<String, String> consumeEvents() {
        return consumer.poll();
    }
}

public class KafkaProducerImpl implements KafkaProducerInterface {
    private final Producer<String, String> producer;

    public KafkaProducerImpl(String bootstrapServers) {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        this.producer = new KafkaProducer<>(props);
    }

    @Override
    public void send(String topic, String message) {
        producer.send(new ProducerRecord<>(topic, message));
    }
}

public class KafkaConsumerImpl implements KafkaConsumerInterface {
    private final Consumer<String, String> consumer;

    public KafkaConsumerImpl(String bootstrapServers, String groupId) {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        this.consumer = new KafkaConsumer<>(props);
    }

    @Override
    public void subscribe(String topic) {
        consumer.subscribe(Collections.singletonList(topic));
    }

    @Override
    public ConsumerRecords<String, String> poll() {
        return consumer.poll(Duration.ofMillis(1000));
    }
}

@Testcontainers
public class KafkaEventProcessorTest {
    @Container
    private static final KafkaContainer kafka = new KafkaContainer(DockerImageName.parse("confluentinc/cp-kafka:latest"));

    @Test
    public void testEventProcessing() {
        String topic = "test-topic";
        String message = "test-message";
        String groupId = UUID.randomUUID().toString();

        KafkaProducerInterface producer = new KafkaProducerImpl(kafka.getBootstrapServers());
        KafkaConsumerInterface consumer = new KafkaConsumerImpl(kafka.getBootstrapServers(), groupId);
        consumer.subscribe(topic);

        KafkaEventProcessor processor = new KafkaEventProcessor(producer, consumer);
        processor.processEvent(topic, message);

        ConsumerRecords<String, String> records = processor.consumeEvents();
        assert !records.isEmpty();
    }
}
