```go
package main

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/gorilla/mux"
	"golang.org/x/crypto/bcrypt"
	"golang.org/x/oauth2"
)

var (
	oauthConfig   *oauth2.Config
	redisClient   *redis.Client
	codeVerifiers = make(map[string]string)
	authCodes     = make(map[string]oauth2.Token)
	accessTokens  = make(map[string]bool)
)

func main() {
	// Initialize Redis
	redisClient = redis.NewClient(&redis.Options{
		Addr: "localhost:6379",
	})

	// OAuth2 configuration
	oauthConfig = &oauth2.Config{
		ClientID:     "your-client-id",
		ClientSecret: "your-client-secret",
		RedirectURL:  "https://your-redirect-url/callback",
		Scopes:       []string{"openid", "profile", "email"},
		Endpoint: oauth2.Endpoint{
			AuthURL:  "https://your-auth-server/authorize",
			TokenURL: "https://your-auth-server/token",
		},
	}

	r := mux.NewRouter()

	// Enforce TLS middleware
	r.Use(enforceTLS)

	// Rate limiting middleware
	r.Use(rateLimit)

	// OAuth endpoints
	r.HandleFunc("/authorize", authorizeHandler).Methods("GET")
	r.HandleFunc("/token", tokenHandler).Methods("POST")
	r.HandleFunc("/revoke", revokeHandler).Methods("POST")

	// Start server with TLS
	log.Fatal(http.ListenAndServeTLS(":443", "server.crt", "server.key", r))
}

func enforceTLS(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.TLS == nil {
			http.Error(w, "TLS required", http.StatusBadRequest)
			auditLog(r, "TLS enforcement failed")
			return
		}
		next.ServeHTTP(w, r)
	})
}

func rateLimit(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		ip := strings.Split(r.RemoteAddr, ":")[0]
		key := "rate_limit:" + ip

		val, err := redisClient.Get(r.Context(), key).Int()
		if err == redis.Nil {
			redisClient.Set(r.Context(), key, 1, time.Minute)
		} else if err != nil {
			http.Error(w, "Internal server error", http.StatusInternalServerError)
			return
		} else if val > 100 {
			http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
			auditLog(r, "Rate limit exceeded")
			return
		} else {
			redisClient.Incr(r.Context(), key)
		}

		next.ServeHTTP(w, r)
	})
}

func authorizeHandler(w http.ResponseWriter, r *http.Request) {
	auditLog(r, "Authorization request started")

	// Validate client_id
	clientID := r.URL.Query().Get("client_id")
	if clientID != oauthConfig.ClientID {
		http.Error(w, "Invalid client_id", http.StatusBadRequest)
		auditLog(r, "Invalid client_id")
		return
	}

	// Validate redirect_uri
	redirectURI := r.URL.Query().Get("redirect_uri")
	if redirectURI != oauthConfig.RedirectURL {
		http.Error(w, "Invalid redirect_uri", http.StatusBadRequest)
		auditLog(r, "Invalid redirect_uri")
		return
	}

	// Generate and store state
	state := generateRandomString(32)
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
	})

	// Handle PKCE
	codeChallenge := r.URL.Query().Get("code_challenge")
	codeChallengeMethod := r.URL.Query().Get("code_challenge_method")
	if codeChallenge == "" || codeChallengeMethod != "S256" {
		http.Error(w, "PKCE code challenge required with S256 method", http.StatusBadRequest)
		auditLog(r, "PKCE validation failed")
		return
	}

	codeVerifier := generateRandomString(64)
	codeVerifiers[state] = codeVerifier

	// Redirect to login page with state and code_challenge
	authURL := oauthConfig.AuthCodeURL(state, oauth2.SetAuthURLParam("code_challenge", codeChallenge), oauth2.SetAuthURLParam("code_challenge_method", codeChallengeMethod))
	http.Redirect(w, r, authURL, http.StatusFound)
	auditLog(r, "Authorization redirect")
}

func tokenHandler(w http.ResponseWriter, r *http.Request) {
	auditLog(r, "Token request started")

	// Parse form data
	err := r.ParseForm()
	if err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		auditLog(r, "Token request parsing failed")
		return
	}

	// Validate grant_type
	grantType := r.FormValue("grant_type")
	if grantType != "authorization_code" {
		http.Error(w, "Unsupported grant_type", http.StatusBadRequest)
		auditLog(r, "Invalid grant_type")
		return
	}

	// Validate code
	code := r.FormValue("code")
	if code == "" {
		http.Error(w, "Code required", http.StatusBadRequest)
		auditLog(r, "Missing authorization code")
		return
	}

	// Validate PKCE code_verifier
	codeVerifier := r.FormValue("code_verifier")
	if codeVerifier == "" {
		http.Error(w, "PKCE code_verifier required", http.StatusBadRequest)
		auditLog(r, "Missing PKCE code_verifier")
		return
	}

	// Verify code_verifier matches code_challenge
	state := r.FormValue("state")
	storedVerifier, exists := codeVerifiers[state]
	if !exists || storedVerifier != codeVerifier {
		http.Error(w, "Invalid code_verifier", http.StatusBadRequest)
		auditLog(r, "PKCE verification failed")
		return
	}

	// Exchange code for token
	token, err := oauthConfig.Exchange(r.Context(), code, oauth2.SetAuthURLParam("code_verifier", codeVerifier))
	if err != nil {
		http.Error(w, "Failed to exchange code for token", http.StatusInternalServerError)
		auditLog(r, "Token exchange failed")
		return
	}

	// Store token and mark as active
	accessTokens[token.AccessToken] = true

	// Return token response
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(token)
	auditLog(r, "Token issued successfully")
}

func revokeHandler(w http.ResponseWriter, r *http.Request) {
	auditLog(r, "Revocation request started")

	token := r.FormValue("token")
	if token == "" {
		http.Error(w, "Token required", http.StatusBadRequest)
		auditLog(r, "Missing token in revocation request")
		return
	}

	// Revoke token by removing from active tokens
	delete(accessTokens, token)

	w.WriteHeader(http.StatusOK)
	auditLog(r, "Token revoked successfully")
}

func generateRandomString(length int) string {
	b := make([]byte, length)
	rand.Read(b)
	return base64.URLEncoding.EncodeToString(b)[:length]
}

func auditLog(r *http.Request, message string) {
	logData := map[string]interface{}{
		"timestamp":   time.Now().UTC().Format(time.RFC3339),
		"ip":         strings.Split(r.RemoteAddr, ":")[0],
		"method":     r.Method,
		"path":       r.URL.Path,
		"user_agent": r.UserAgent(),
		"message":    message,
	}

	logBytes, _ := json.Marshal(logData)
	redisClient.LPush(r.Context(), "audit_logs", string(logBytes))
}
