```cpp
#include <iostream>
#include <fstream>
#include <vector>
#include <queue>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <algorithm>
#include <chrono>
#include <sstream>
#include <cstring>

const size_t MAX_MEMORY = 6ULL * 1024 * 1024 * 1024; // 6GB buffer (leaving 2GB for system)
const size_t CHUNK_SIZE = 256 * 1024 * 1024; // 256MB chunks
const int NUM_THREADS = std::thread::hardware_concurrency();

std::mutex io_mutex;
std::condition_variable cv;
bool io_complete = false;

struct Chunk {
    std::string filename;
    size_t size;
    std::ifstream::pos_type start_pos;
};

void sort_chunk(const std::vector<uint64_t>& data, const std::string& filename) {
    std::vector<uint64_t> sorted_data(data);
    std::sort(sorted_data.begin(), sorted_data.end());

    std::ofstream out(filename, std::ios::binary | std::ios::out);
    out.write(reinterpret_cast<const char*>(sorted_data.data()), sorted_data.size() * sizeof(uint64_t));
    out.close();
}

void read_chunk(const std::string& input_file, size_t start, size_t end, std::vector<uint64_t>& buffer) {
    std::ifstream in(input_file, std::ios::binary | std::ios::in);
    in.seekg(start);
    size_t elements = (end - start) / sizeof(uint64_t);
    buffer.resize(elements);
    in.read(reinterpret_cast<char*>(buffer.data()), end - start);
    in.close();
}

void merge_files(const std::vector<Chunk>& chunks, const std::string& output_file) {
    std::vector<std::ifstream> files(chunks.size());
    std::vector<uint64_t> current_values(chunks.size());
    std::priority_queue<std::pair<uint64_t, size_t>, 
                        std::vector<std::pair<uint64_t, size_t>>,
                        std::greater<std::pair<uint64_t, size_t>>> min_heap;

    // Open all chunk files
    for (size_t i = 0; i < chunks.size(); ++i) {
        files[i].open(chunks[i].filename, std::ios::binary);
        files[i].read(reinterpret_cast<char*>(&current_values[i]), sizeof(uint64_t));
        min_heap.emplace(current_values[i], i);
    }

    std::ofstream out(output_file, std::ios::binary | std::ios::out);
    std::vector<char> write_buffer(64 * 1024 * 1024); // 64MB write buffer
    size_t buffer_pos = 0;

    while (!min_heap.empty()) {
        auto smallest = min_heap.top();
        min_heap.pop();

        // Write to buffer
        if (buffer_pos + sizeof(uint64_t) > write_buffer.size()) {
            out.write(write_buffer.data(), buffer_pos);
            buffer_pos = 0;
        }
        std::memcpy(write_buffer.data() + buffer_pos, &smallest.first, sizeof(uint64_t));
        buffer_pos += sizeof(uint64_t);

        // Read next element from the same file
        if (files[smallest.second].read(reinterpret_cast<char*>(&current_values[smallest.second]), sizeof(uint64_t))) {
            min_heap.emplace(current_values[smallest.second], smallest.second);
        }
    }

    // Flush remaining buffer
    if (buffer_pos > 0) {
        out.write(write_buffer.data(), buffer_pos);
    }

    // Close all files
    for (auto& file : files) {
        file.close();
    }
    out.close();
}

void io_worker(const std::string& input_file, std::vector<Chunk>& chunks) {
    std::ifstream in(input_file, std::ios::binary | std::ios::ate);
    size_t file_size = in.tellg();
    in.close();

    size_t pos = 0;
    while (pos < file_size) {
        size_t end_pos = std::min(pos + CHUNK_SIZE, file_size);
        std::vector<uint64_t> buffer;
        read_chunk(input_file, pos, end_pos, buffer);

        std::string chunk_filename = "chunk_" + std::to_string(chunks.size()) + ".bin";
        sort_chunk(buffer, chunk_filename);

        {
            std::lock_guard<std::mutex> lock(io_mutex);
            chunks.push_back({chunk_filename, buffer.size() * sizeof(uint64_t), pos});
        }

        pos = end_pos;
    }

    {
        std::lock_guard<std::mutex> lock(io_mutex);
        io_complete = true;
    }
    cv.notify_all();
}

void external_sort(const std::string& input_file, const std::string& output_file) {
    auto start_time = std::chrono::high_resolution_clock::now();
    std::vector<Chunk> chunks;

    // Start IO worker thread
    std::thread io_thread(io_worker, input_file, std::ref(chunks));

    // Wait for IO to complete
    {
        std::unique_lock<std::mutex> lock(io_mutex);
        cv.wait(lock, []{ return io_complete; });
    }
    io_thread.join();

    auto io_end_time = std::chrono::high_resolution_clock::now();

    // Merge sorted chunks
    merge_files(chunks, output_file);

    auto end_time = std::chrono::high_resolution_clock::now();

    // Clean up temporary files
    for (const auto& chunk : chunks) {
        std::remove(chunk.filename.c_str());
    }

    // Benchmark results
    auto io_duration = std::chrono::duration_cast<std::chrono::milliseconds>(io_end_time - start_time);
    auto merge_duration = std::chrono::duration_cast<std::chrono::milliseconds>(end_time - io_end_time);
    auto total_duration = std::chronio::duration_cast<std::chrono::milliseconds>(end_time - start_time);

    std::cout << "Benchmark Results:\n";
    std::cout << "IO Phase: " << io_duration.count() << "ms\n";
    std::cout << "Merge Phase: " << merge_duration.count() << "ms\n";
    std::cout << "Total Time: " << total_duration.count() << "ms\n";
    std::cout << "Throughput: " << (100ULL * 1024 * 1024 * 1024) / (total_duration.count() * 1000) << " MB/s\n";
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <input_file> <output_file>\n";
        return 1;
    }

    external_sort(argv[1], argv[2]);
    return 0;
}
