import importlib
import pkgutil
from abc import ABC, abstractmethod
from typing import Dict, List, Optional, Tuple
import networkx as nx

class GraphSearchPlugin(ABC):
    """Base class for graph search plugins."""

    @classmethod
    @abstractmethod
    def name(cls) -> str:
        """Return the name of the algorithm."""
        pass

    @abstractmethod
    def search(self, graph: nx.Graph, start: str, end: str) -> Tuple[List[str], float]:
        """Perform the search and return the path and cost."""
        pass

class PluginManager:
    """Manages the discovery and loading of plugins."""

    def __init__(self, plugin_package: str = "plugins"):
        self.plugin_package = plugin_package
        self.plugins: Dict[str, GraphSearchPlugin] = {}
        self._discover_plugins()

    def _discover_plugins(self) -> None:
        """Discover and load all plugins in the specified package."""
        package = importlib.import_module(self.plugin_package)
        for _, module_name, _ in pkgutil.iter_modules(package.__path__):
            module = importlib.import_module(f"{self.plugin_package}.{module_name}")
            for attribute_name in dir(module):
                attribute = getattr(module, attribute_name)
                if (
                    isinstance(attribute, type)
                    and issubclass(attribute, GraphSearchPlugin)
                    and attribute is not GraphSearchPlugin
                ):
                    plugin = attribute()
                    self.plugins[plugin.name()] = plugin

    def get_plugin(self, name: str) -> Optional[GraphSearchPlugin]:
        """Retrieve a plugin by name."""
        return self.plugins.get(name)

class GraphSearchFramework:
    """Framework for executing graph search algorithms."""

    def __init__(self, plugin_package: str = "plugins"):
        self.plugin_manager = PluginManager(plugin_package)

    def search(
        self, algorithm: str, graph: nx.Graph, start: str, end: str
    ) -> Tuple[List[str], float]:
        """Execute the specified search algorithm."""
        plugin = self.plugin_manager.get_plugin(algorithm)
        if not plugin:
            raise ValueError(f"Algorithm '{algorithm}' not found.")
        return plugin.search(graph, start, end)

# Example plugin implementation (Dijkstra)
class DijkstraPlugin(GraphSearchPlugin):
    @classmethod
    def name(cls) -> str:
        return "dijkstra"

    def search(self, graph: nx.Graph, start: str, end: str) -> Tuple[List[str], float]:
        try:
            path = nx.dijkstra_path(graph, start, end)
            cost = nx.dijkstra_path_length(graph, start, end)
            return path, cost
        except nx.NetworkXNoPath:
            return [], float("inf")

# Example plugin implementation (A*)
class AStarPlugin(GraphSearchPlugin):
    @classmethod
    def name(cls) -> str:
        return "a_star"

    def search(self, graph: nx.Graph, start: str, end: str) -> Tuple[List[str], float]:
        try:
            path = nx.astar_path(graph, start, end)
            cost = nx.astar_path_length(graph, start, end)
            return path, cost
        except nx.NetworkXNoPath:
            return [], float("inf")

# Example plugin implementation (Bellman-Ford)
class BellmanFordPlugin(GraphSearchPlugin):
    @classmethod
    def name(cls) -> str:
        return "bellman_ford"

    def search(self, graph: nx.Graph, start: str, end: str) -> Tuple[List[str], float]:
        try:
            path = nx.bellman_ford_path(graph, start, end)
            cost = nx.bellman_ford_path_length(graph, start, end)
            return path, cost
        except nx.NetworkXNoPath:
