use std::cmp::{max, Ordering};

// Core trait for knapsack solvers
pub trait KnapsackSolver {
    fn solve(&self, capacity: u32, weights: &[u32], values: &[u32]) -> (u32, Vec<usize>);
}

// Dynamic Programming solver
pub struct DPKnapsackSolver;

impl KnapsackSolver for DPKnapsackSolver {
    fn solve(&self, capacity: u32, weights: &[u32], values: &[u32]) -> (u32, Vec<usize>) {
        let n = weights.len();
        let mut dp = vec![vec![0; capacity as usize + 1]; n + 1];

        for i in 1..=n {
            for w in 1..=capacity as usize {
                if weights[i - 1] as usize <= w {
                    dp[i][w] = max(
                        values[i - 1] + dp[i - 1][w - weights[i - 1] as usize],
                        dp[i - 1][w],
                    );
                } else {
                    dp[i][w] = dp[i - 1][w];
                }
            }
        }

        let mut res = dp[n][capacity as usize];
        let mut w = capacity as usize;
        let mut items = Vec::new();

        for i in (1..=n).rev() {
            if res <= 0 {
                break;
            }
            if res == dp[i - 1][w] {
                continue;
            } else {
                items.push(i - 1);
                res -= values[i - 1];
                w -= weights[i - 1] as usize;
            }
        }

        (dp[n][capacity as usize], items)
    }
}

// Branch and Bound solver
pub struct BBKnapsackSolver;

impl KnapsackSolver for BBKnapsackSolver {
    fn solve(&self, capacity: u32, weights: &[u32], values: &[u32]) -> (u32, Vec<usize>) {
        #[derive(Debug, Clone)]
        struct Node {
            level: usize,
            profit: u32,
            bound: f64,
            weight: u32,
        }

        let n = weights.len();
        let mut items: Vec<_> = (0..n)
            .map(|i| (values[i] as f64 / weights[i] as f64, i))
            .collect();
        items.sort_by(|a, b| b.partial_cmp(a).unwrap_or(Ordering::Equal));

        let mut queue = Vec::new();
        let mut max_profit = 0;
        let mut best_items = Vec::new();

        let root = Node {
            level: 0,
            profit: 0,
            bound: 0.0,
            weight: 0,
        };
        queue.push(root);

        while let Some(node) = queue.pop() {
            if node.bound > max_profit as f64 && node.level < n {
                let i = items[node.level].1;

                // Include next item
                let mut next = node.clone();
                next.level += 1;
                next.weight += weights[i];
                next.profit += values[i];

                if next.weight <= capacity && next.profit > max_profit {
                    max_profit = next.profit;
                    best_items = vec![i];
                }

                next.bound = bound(
                    next.level,
                    next.weight,
                    next.profit,
                    capacity,
                    &items,
                    weights,
                    values,
                );

                if next.bound > max_profit as f64 {
                    queue.push(next);
                }

                // Exclude next item
                let mut next = node.clone();
                next.level += 1;
                next.bound = bound(
                    next.level,
                    next.weight,
                    next.profit,
                    capacity,
                    &items,
                    weights,
                    values,
                );

                if next.bound > max_profit as f64 {
                    queue.push(next);
                }
            }
        }

        (max_profit, best_items)
    }
}

fn bound(
    level: usize,
    weight: u32,
    profit: u32,
    capacity: u32,
    items: &[(f64, usize)],
    weights: &[u32],
    values: &[u32],
) -> f64 {
    if weight >= capacity {
        return profit as f64;
    }

    let mut bound = profit as f64;
    let mut total_weight = weight;
    let mut i = level;

    while i < items.len() && total_weight + weights[items[i].1] <= capacity {
        total_weight += weights[items[i].1];
        bound += values[items[i].1] as f64;
        i += 1;
    }

    if i < items.len() {
        bound += (capacity - total_weight) as f64 * items[i].0;
    }

    bound
}

// Greedy solver
pub struct GreedyKnapsackSolver;

impl KnapsackSolver for GreedyKnapsackSolver {
    fn solve(&self, capacity: u32, weights: &[u32], values: &[u32]) -> (u32, Vec<usize>) {
        let n = weights.len();
        let mut items: Vec<_> = (0..n)
            .map(|i| (values[i] as f64 / weights[i] as f64, i))
            .collect();
        items.sort_by(|a, b| b.partial_cmp(a).unwrap_or(Ordering::Equal));

        let mut total_value = 0;
        let mut total_weight = 0;
        let mut selected = Vec::new();

        for (_, i) in items {
            if total_weight + weights[i] <= capacity {
                selected.push(i);
                total_value += values[i];
                total_weight += weights[i];
            }
        }

        (total_value, selected)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;

    proptest! {
        #[test]
        fn test_dp_solver(capacity in 1..100u32, items in prop::collection::vec((1..100u32, 1..100u32), 1..20)) {
            let (weights, values): (Vec<_>, Vec<_>) = items.into_iter().unzip();
            let solver = DPKnapsackSolver;
