```go
package main

import (
	"log"
	"math/rand"
	"sync"
	"time"
)

// Node represents a single node in the distributed system
type Node struct {
	ID          int
	State       string
	CurrentTerm int
	VotedFor    int
	Log         []LogEntry
	CommitIndex int
	LastApplied int
	NextIndex   map[int]int
	MatchIndex  map[int]int
	Peers       []*Node
	LeaderID    int
	mu          sync.Mutex
	stopCh      chan struct{}
}

// LogEntry represents a log entry
type LogEntry struct {
	Term    int
	Command interface{}
}

// Message represents a message sent between nodes
type Message struct {
	From    int
	To      int
	Term    int
	Type    string
	Success bool
	Entries []LogEntry
}

// Simulator manages the distributed consensus simulation
type Simulator struct {
	Nodes       []*Node
	Network     chan Message
	Partitions  map[int]bool
	FaultyNodes map[int]bool
}

func NewSimulator(nodeCount int) *Simulator {
	sim := &Simulator{
		Network:     make(chan Message, 100),
		Partitions:  make(map[int]bool),
		FaultyNodes: make(map[int]bool),
	}

	for i := 0; i < nodeCount; i++ {
		node := &Node{
			ID:          i,
			State:       "follower",
			CurrentTerm: 0,
			VotedFor:    -1,
			Log:         make([]LogEntry, 0),
			NextIndex:   make(map[int]int),
			MatchIndex:  make(map[int]int),
			stopCh:      make(chan struct{}),
		}
		sim.Nodes = append(sim.Nodes, node)
	}

	// Set peers for each node
	for _, node := range sim.Nodes {
		for _, peer := range sim.Nodes {
			if peer.ID != node.ID {
				node.Peers = append(node.Peers, peer)
			}
		}
	}

	return sim
}

func (s *Simulator) Start() {
	for _, node := range s.Nodes {
		go node.Run(s)
	}
}

func (s *Simulator) Stop() {
	for _, node := range s.Nodes {
		close(node.stopCh)
	}
}

func (s *Simulator) InjectFault(nodeID int) {
	s.FaultyNodes[nodeID] = true
	log.Printf("Injected fault in node %d", nodeID)
}

func (s *Simulator) Partition(nodeID int) {
	s.Partitions[nodeID] = true
	log.Printf("Partitioned node %d", nodeID)
}

func (s *Simulator) Heal(nodeID int) {
	delete(s.FaultyNodes, nodeID)
	delete(s.Partitions, nodeID)
	log.Printf("Healed node %d", nodeID)
}

func (n *Node) Run(sim *Simulator) {
	electionTimeout := time.Duration(150+rand.Intn(150)) * time.Millisecond
	heartbeatInterval := 50 * time.Millisecond

	electionTimer := time.NewTimer(electionTimeout)
	defer electionTimer.Stop()

	heartbeatTimer := time.NewTimer(heartbeatInterval)
	defer heartbeatTimer.Stop()

	for {
		select {
		case <-n.stopCh:
			return

		case msg := <-sim.Network:
			if sim.Partitions[msg.To] || sim.FaultyNodes[msg.To] {
				continue
			}

			n.mu.Lock()
			switch msg.Type {
			case "RequestVote":
				n.handleRequestVote(msg, sim)
			case "AppendEntries":
				n.handleAppendEntries(msg, sim)
			}
			n.mu.Unlock()

		case <-electionTimer.C:
			n.mu.Lock()
			if n.State != "leader" && !sim.FaultyNodes[n.ID] {
				n.startElection(sim)
			}
			electionTimer.Reset(time.Duration(150+rand.Intn(150)) * time.Millisecond)
			n.mu.Unlock()

		case <-heartbeatTimer.C:
			n.mu.Lock()
			if n.State == "leader" && !sim.FaultyNodes[n.ID] {
				n.sendHeartbeats(sim)
			}
			heartbeatTimer.Reset(heartbeatInterval)
			n.mu.Unlock()
		}
	}
}

func (n *Node) startElection(sim *Simulator) {
	n.CurrentTerm++
	n.State = "candidate"
	n.VotedFor = n.ID
	votes := 1

	log.Printf("Node %d starting election for term %d", n.ID, n.CurrentTerm)

	for _, peer := range n.Peers {
		if sim.Partitions[peer.ID] || sim.FaultyNodes[peer.ID] {
			continue
		}

		msg := Message{
			From: n.ID,
			To:   peer.ID,
			Term: n.CurrentTerm,
			Type: "RequestVote",
		}

		sim.Network <- msg
	}

	// Simulate vote collection (simplified)
	for _, peer := range n.Peers {
		if !sim.Partitions[peer.ID] && !sim.FaultyNodes[peer.ID] && rand.Float32() > 0.3 {
			votes++
		}
	}

	if votes > len(n.Peers)/2 {
		n.State = "leader"
		n.LeaderID = n.ID
		log.Printf("Node %d elected leader for term %d", n.ID, n.CurrentTerm)
	} else {
		n.State = "follower"
		log.Printf("Node %d lost election for term %d", n.ID, n.CurrentTerm)
	}
}

func (n *Node) handleRequestVote(msg Message, sim *Simulator) {
	reply := Message{
		From: n.ID,
		To:   msg.From,
		Term: n.CurrentTerm,
		Type: "RequestVoteReply",
	}

	if msg.Term > n.CurrentTerm {
		n.CurrentTerm = msg.Term
		n.State = "follower"
		n.VotedFor = -1
	}

	if (n.VotedFor == -1 || n.VotedFor == msg.From) && msg.Term >= n.CurrentTerm {
		n.VotedFor = msg.From
		reply.Success = true
	} else {
		reply.Success = false
	}

	sim.Network <- reply
}

func (n *Node) sendHeartbeats(sim *Simulator) {
	for _, peer := range n.Peers {
		if sim.Partitions[peer.ID] || sim.FaultyNodes[peer.ID] {
			continue
		}

		msg := Message{
			From:    n.ID,
			To:      peer.ID,
			Term:    n.CurrentTerm,
			Type:    "AppendEntries",
			Entries: []LogEntry{},
		}

		sim.Network <- msg
	}
}

func (n *Node) handleAppendEntries(msg Message, sim *Simulator) {
	reply := Message{
		From: n.ID,
		To:   msg.From,
		Term: n.CurrentTerm,
		Type: "AppendEntriesReply",
	}

	if msg.Term >= n.CurrentTerm {
		n.CurrentTerm = msg.Term
		n.State = "follower"
		n.LeaderID = msg.From
		reply.Success = true
	} else {
		reply.Success = false
	}

	sim.Network <- reply
}

func main() {
	rand.Seed(time.Now().UnixNano())

	sim := NewSimulator(5)
	sim.Start()

	// Run fault injection tests
	time.Sleep(1 * time.Second)
	sim.InjectFault(2)
	sim.Partition(3)

	time.Sleep(2 * time.Second)
	sim.Heal(2)
	sim.Heal(3)

	time.Sleep(2 * time.Second)
	sim.Stop()
}
