import akka.actor.{Actor, ActorRef, ActorSystem, Props}
import akka.stream.{ActorMaterializer, ThrottleMode}
import akka.stream.scaladsl.{Sink, Source}
import scala.concurrent.duration._
import scala.collection.mutable

// Message types
case class Document(text: String)
case class WordCount(word: String, count: Int)
case class MapTask(doc: Document, replyTo: ActorRef)
case class ReduceTask(word: String, counts: Seq[Int], replyTo: ActorRef)
case object TaskAck
case object RequestWork
case class WorkAvailable(hasWork: Boolean)

// Mapper Actor
class Mapper extends Actor {
  def receive: Receive = {
    case MapTask(doc, replyTo) =>
      val words = doc.text.split("\\W+").filter(_.nonEmpty)
      val counts = words.groupBy(identity).mapValues(_.length)
      counts.foreach { case (word, count) =>
        replyTo ! WordCount(word, count)
      }
      sender() ! TaskAck
  }
}

// Reducer Actor
class Reducer extends Actor {
  private val counts = mutable.Map[String, Int]().withDefaultValue(0)

  def receive: Receive = {
    case WordCount(word, count) =>
      counts(word) += count
    case ReduceTask(word, _, replyTo) =>
      replyTo ! WordCount(word, counts(word))
      sender() ! TaskAck
  }
}

// Master Actor with backpressure
class Master(numMappers: Int, numReducers: Int) extends Actor {
  private val mappers = Vector.fill(numMappers)(context.actorOf(Props[Mapper]()))
  private val reducers = Vector.fill(numReducers)(context.actorOf(Props[Reducer]()))
  private var pendingAcks = 0
  private var isThrottled = false

  def receive: Receive = {
    case doc: Document =>
      if (!isThrottled) {
        val mapper = mappers(pendingAcks % numMappers)
        mapper ! MapTask(doc, self)
        pendingAcks += 1
        if (pendingAcks > 1000) { // Backpressure threshold
          isThrottled = true
          context.system.scheduler.scheduleOnce(1.second, self, "unthrottle")(context.dispatcher)
        }
      }

    case "unthrottle" =>
      isThrottled = false

    case WordCount(word, count) =>
      val reducer = reducers(math.abs(word.hashCode) % numReducers)
      reducer ! WordCount(word, count)

    case TaskAck =>
      pendingAcks -= 1
  }
}

// Cluster setup
object WordCountCluster {
  def main(args: Array[String]): Unit = {
    implicit val system: ActorSystem = ActorSystem("WordCountCluster")
    implicit val materializer: ActorMaterializer = ActorMaterializer()

    val master = system.actorOf(Props(new Master(10, 10)), "master")

    // Simulate document source with backpressure
    Source(1 to 1000000)
      .map(i => Document(s"doc$i contains words ${i % 100}"))
      .throttle(
        elements = 1000,
        per = 1.second,
        maximumBurst = 1000,
        mode = ThrottleMode.shaping
      )
      .runWith(Sink.actorRef(master, onCompleteMessage = "stream completed"))
  }
}
