```javascript
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sorting Algorithm Visualizer</title>
    <script src="https://d3js.org/d3.v7.min.js"></script>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
        }
        .controls {
            margin-bottom: 20px;
        }
        .array-container {
            display: flex;
            margin-bottom: 20px;
        }
        .array-bar {
            margin-right: 2px;
            background-color: steelblue;
            text-align: center;
            color: white;
            font-size: 12px;
        }
        .annotation {
            margin-top: 10px;
            padding: 10px;
            background-color: #f0f0f0;
            border-radius: 5px;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Visualizer</h1>

    <div class="controls">
        <label for="algorithm">Algorithm:</label>
        <select id="algorithm">
            <option value="merge">Merge Sort</option>
            <option value="quick">Quick Sort</option>
            <option value="heap">Heap Sort</option>
        </select>

        <label for="speed">Speed:</label>
        <input type="range" id="speed" min="1" max="10" value="5">

        <button id="start">Start</button>
        <button id="pause">Pause</button>
        <button id="step">Step</button>
        <button id="reset">Reset</button>
    </div>

    <div id="visualization"></div>
    <div id="annotation" class="annotation"></div>

    <script>
        const width = 800;
        const height = 400;
        const margin = { top: 20, right: 20, bottom: 30, left: 40 };

        let data = [];
        let animationId = null;
        let isPaused = false;
        let speed = 5;
        let currentStep = 0;
        let steps = [];

        const svg = d3.select("#visualization")
            .append("svg")
            .attr("width", width)
            .attr("height", height);

        function generateRandomData(size = 20) {
            return Array.from({ length: size }, () => Math.floor(Math.random() * 100) + 1);
        }

        function visualizeData(data, highlights = []) {
            svg.selectAll("*").remove();

            const xScale = d3.scaleBand()
                .domain(d3.range(data.length))
                .range([margin.left, width - margin.right])
                .padding(0.1);

            const yScale = d3.scaleLinear()
                .domain([0, d3.max(data)])
                .range([height - margin.bottom, margin.top]);

            svg.selectAll("rect")
                .data(data)
                .enter()
                .append("rect")
                .attr("x", (d, i) => xScale(i))
                .attr("y", d => yScale(d))
                .attr("width", xScale.bandwidth())
                .attr("height", d => height - margin.bottom - yScale(d))
                .attr("fill", (d, i) => highlights.includes(i) ? "red" : "steelblue");

            svg.selectAll("text")
                .data(data)
                .enter()
                .append("text")
                .text(d => d)
                .attr("x", (d, i) => xScale(i) + xScale.bandwidth() / 2)
                .attr("y", d => yScale(d) - 5)
                .attr("text-anchor", "middle")
                .attr("font-size", "10px")
                .attr("fill", "white");
        }

        function updateAnnotation(text) {
            d3.select("#annotation").text(text);
        }

        function* mergeSort(arr, start = 0) {
            if (arr.length <= 1) return arr;

            const mid = Math.floor(arr.length / 2);
            const left = arr.slice(0, mid);
            const right = arr.slice(mid);

            updateAnnotation(`Splitting array from index ${start} to ${start + arr.length - 1}`);
            yield { data: [...data], highlights: Array.from({ length: arr.length }, (_, i) => start + i) };

            const leftSorted = yield* mergeSort(left, start);
            const rightSorted = yield* mergeSort(right, start + mid);

            const merged = [];
            let i = 0, j = 0;

            while (i < leftSorted.length && j < rightSorted.length) {
                if (leftSorted[i] < rightSorted[j]) {
                    merged.push(leftSorted[i++]);
                } else {
                    merged.push(rightSorted[j++]);
                }

                const newData = [...data];
                newData.splice(start, merged.length, ...merged);
                newData.splice(start + merged.length, leftSorted.length - i, ...leftSorted.slice(i));
                newData.splice(start + merged.length + leftSorted.length - i, rightSorted.length - j, ...rightSorted.slice(j));

                updateAnnotation(`Merging elements at positions ${start + i} and ${start + mid + j}`);
                yield { data: newData, highlights: [start + i, start + mid + j] };
            }

            while (i < leftSorted.length) {
                merged.push(leftSorted[i++]);

                const newData = [...data];
                newData.splice(start, merged.length, ...merged);
                newData.splice(start + merged.length, leftSorted.length - i, ...leftSorted.slice(i));

                updateAnnotation(`Adding remaining left element at position ${start + i - 1}`);
                yield { data: newData, highlights: [start + i - 1] };
            }

            while (j < rightSorted.length) {
                merged.push(rightSorted[j++]);

                const newData = [...data];
                newData.splice(start, merged.length, ...merged);
                newData.splice(start + merged.length, rightSorted.length - j, ...rightSorted.slice(j));

                updateAnnotation(`Adding remaining right element at position ${start + mid + j - 1}`);
                yield { data: newData, highlights: [start + mid + j - 1] };
            }

            return merged;
        }

        function* quickSort(arr, low = 0, high = arr.length - 1) {
            if (low < high) {
                const partitionGen = partition(arr, low, high);
                let result = partitionGen.next();

                while (!result.done) {
                    yield result.value;
                    result = partitionGen.next();
                }

                const pi = result.value;

                yield* quickSort(arr, low, pi - 1);
                yield* quickSort(arr, pi + 1, high);
            }
        }

        function* partition(arr, low, high) {
            const pivot = arr[high];
            let i = low - 1;

            updateAnnotation(`Partitioning from ${low} to ${high} with pivot ${pivot}`);
            yield { data: [...data], highlights: [high] };

            for (let j = low; j < high; j++) {
                if (arr[j] < pivot) {
                    i++;
                    [arr[i], arr[j]] = [arr[j], arr[i]];

                    const newData = [...data];
                    [newData[i], newData[j]] = [newData[j], newData[i]];

                    updateAnnotation(`Swapping elements at positions ${i} and ${j}`);
                    yield { data: newData, highlights: [i, j] };
                }
            }

            [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];

            const newData = [...data];
            [newData[i + 1], newData[high]] = [newData[high], newData[i + 1]];

            updateAnnotation(`Placing pivot at correct position ${i + 1}`);
            yield { data: newData, highlights: [i + 1, high] };

            return i + 1;
        }

        function* heapSort(arr) {
            const n = arr.length;

            for (let i = Math.floor(n / 2) - 1; i >= 0; i--) {
                yield* heapify(arr, n, i);
            }

            for (let i = n - 1; i > 0; i--) {
                [arr[0], arr[i]] = [arr[i], arr[0]];

                const newData = [...data];
                [newData[0], newData[i]] = [newData[i], newData[0]];

                updateAnnotation(`Moving current root (${arr[i]}) to end at position ${i}`);
                yield { data: newData, highlights: [0, i] };

                yield* heapify(arr, i, 0);
            }
        }

        function* heapify(arr, n, i) {
            let largest = i;
            const left = 2 * i + 1;
            const right = 2 * i + 2;

            if (left < n && arr[left] > arr[largest]) {
                largest = left;
            }

            if (right < n && arr[right] > arr[largest]) {
                largest = right;
            }

            if (largest !== i) {
                [arr[i], arr[largest]] = [arr[largest], arr[i]];

                const newData = [...data];
                [newData[i], newData[largest]] = [newData[largest], newData[i]];

                updateAnnotation(`Heapifying subtree rooted at ${i}, swapping with ${largest}`);
                yield { data: newData, highlights: [i, largest] };

                yield* heapify(arr, n, largest);
            }
        }

        function startVisualization() {
            if (animationId) {
                cancelAnimationFrame(animationId);
            }

            const algorithm = document.getElementById("algorithm").value;
            data = generateRandomData();
            visualizeData(data);
            updateAnnotation("Initial array");

            let generator;

            if (algorithm === "merge") {
                generator = mergeSort([...data]);
            } else if (algorithm === "quick") {
                generator = quickSort([...data]);
            } else if (algorithm === "heap") {
                generator = heapSort([...data]);
            }

            steps = [];
            let result = generator.next();

            while (!result.done) {
                steps.push(result.value);
                result = generator.next();
            }

            currentStep = 0;
            isPaused = false;
            animate();
        }

        function animate() {
            if (currentStep >= steps.length || isPaused) return;

            const step = steps[currentStep];
            data = step.data;
            visualizeData(data, step.highlights);

            currentStep++;

            if (currentStep < steps.length) {
                animationId = setTimeout(() => {
                    animate();
                }, 1000 / speed);
            } else {
                updateAnnotation("Sorting complete!");
            }
        }

        function pauseVisualization() {
            isPaused = true;
            if (animationId) {
                clearTimeout(animationId);
            }
        }

        function stepVisualization() {
            if (currentStep >= steps.length) return;

            pauseVisualization();

            const step = steps[currentStep];
            data = step.data;
            visualizeData(data, step.highlights);

            currentStep++;

            if (currentStep >= steps.length) {
                updateAnnotation("Sorting complete!");
            }
        }

        function resetVisualization() {
            pauseVisualization();
            data = generateRandomData();
            visualizeData(data);
            updateAnnotation("Array reset");
            currentStep = 0;
        }

        document.getElementById("start").addEventListener("click", startVisualization);
        document.getElementById("pause").addEventListener("click", pauseVisualization);
        document.getElementById("step").addEventListener("click", stepVisualization);
        document.getElementById("reset").addEventListener("click", resetVisualization);
        document.getElementById("speed").addEventListener("input", (e) => {
            speed = parseInt(e.target.value);
        });

        // Initialize
        data = generateRandomData();
        visualizeData(data);
        updateAnnotation("Initial array");
    </script>
</body>
</html>
