```c
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <x86intrin.h>
#include <time.h>
#include <fftw3.h>

#define N (1 << 20)  // 1 million points
#define ALIGN 64

typedef struct {
    float re;
    float im;
} complex_t;

static inline complex_t complex_add(complex_t a, complex_t b) {
    return (complex_t){a.re + b.re, a.im + b.im};
}

static inline complex_t complex_sub(complex_t a, complex_t b) {
    return (complex_t){a.re - b.re, a.im - b.im};
}

static inline complex_t complex_mul(complex_t a, complex_t b) {
    return (complex_t){a.re * b.re - a.im * b.im, a.re * b.im + a.im * b.re};
}

void fft_simd(complex_t* x, int n) {
    if (n <= 1) return;

    // Split even and odd
    complex_t* even = _mm_malloc(n/2 * sizeof(complex_t), ALIGN);
    complex_t* odd = _mm_malloc(n/2 * sizeof(complex_t), ALIGN);

    for (int i = 0; i < n/2; i++) {
        even[i] = x[2*i];
        odd[i] = x[2*i + 1];
    }

    // Recursive calls
    fft_simd(even, n/2);
    fft_simd(odd, n/2);

    // Combine results with SIMD
    for (int k = 0; k < n/2; k += 4) {
        __m128 theta = _mm_set_ps(-2*M_PI*(k+3)/n, -2*M_PI*(k+2)/n, 
                                 -2*M_PI*(k+1)/n, -2*M_PI*k/n);
        __m128 w_re = _mm_cos_ps(theta);
        __m128 w_im = _mm_sin_ps(theta);

        __m128 even_re = _mm_load_ps(&even[k].re);
        __m128 even_im = _mm_load_ps(&even[k].im);
        __m128 odd_re = _mm_load_ps(&odd[k].re);
        __m128 odd_im = _mm_load_ps(&odd[k].im);

        __m128 t_re = _mm_sub_ps(_mm_mul_ps(odd_re, w_re), 
                                _mm_mul_ps(odd_im, w_im));
        __m128 t_im = _mm_add_ps(_mm_mul_ps(odd_re, w_im), 
                                _mm_mul_ps(odd_im, w_re));

        __m128 x_k_re = _mm_add_ps(even_re, t_re);
        __m128 x_k_im = _mm_add_ps(even_im, t_im);
        __m128 x_nk_re = _mm_sub_ps(even_re, t_re);
        __m128 x_nk_im = _mm_sub_ps(even_im, t_im);

        _mm_store_ps(&x[k].re, x_k_re);
        _mm_store_ps(&x[k].im, x_k_im);
        _mm_store_ps(&x[k + n/2].re, x_nk_re);
        _mm_store_ps(&x[k + n/2].im, x_nk_im);
    }

    _mm_free(even);
    _mm_free(odd);
}

int main() {
    complex_t* data = _mm_malloc(N * sizeof(complex_t), ALIGN);

    // Initialize with random data
    for (int i = 0; i < N; i++) {
        data[i].re = (float)rand() / RAND_MAX;
        data[i].im = (float)rand() / RAND_MAX;
    }

    // Measure SIMD FFT
    unsigned long long start = __rdtsc();
    fft_simd(data, N);
    unsigned long long end = __rdtsc();
    double simd_time = (end - start) / 2.6e9 * 1000; // Convert cycles to ms

    // Measure FFTW
    fftwf_complex *in, *out;
    fftwf_plan p;

    in = (fftwf_complex*) fftwf_malloc(sizeof(fftwf_complex) * N);
    out = (fftwf_complex*) fftwf_malloc(sizeof(fftwf_complex) * N);

    for (int i = 0; i < N; i++) {
        in[i][0] = data[i].re;
        in[i][1] = data[i].im;
    }

    start = __rdtsc();
    p = fftwf_plan_dft_1d(N, in, out, FFTW_FORWARD, FFTW_ESTIMATE);
    fftwf_execute(p);
    end = __rdtsc();
    double fftw_time = (end - start) / 2.6e9 * 1000;

    printf("SIMD FFT time: %.2f ms\n", simd_time);
    printf("FFTW time: %.2f ms\n", fftw_time);

    _mm_free(data);
    fftwf_destroy_plan(p);
    fftwf_free(in);
    fftwf_free(out);

    return 0;
}
