import time
import hashlib
import numpy as np
from typing import List, Dict, Any
from functools import wraps
from collections import defaultdict

# Rate limiting decorator
def rate_limit(max_calls: int, time_frame: int):
    def decorator(func):
        calls = []

        @wraps(func)
        def wrapper(*args, **kwargs):
            now = time.time()
            calls_in_time = [call for call in calls if call > now - time_frame]

            if len(calls_in_time) >= max_calls:
                raise Exception("Rate limit exceeded")

            calls.append(now)
            return func(*args, **kwargs)
        return wrapper
    return decorator

# Constant-time hash function
def constant_time_hash(data: str) -> str:
    # Use HMAC with a fixed-time comparison
    h = hashlib.sha256()
    h.update(data.encode('utf-8'))
    return h.hexdigest()

# Validate input (e.g., ensure vectors are of the same dimension)
def validate_input(vector: List[float], dimension: int) -> None:
    if len(vector) != dimension:
        raise ValueError("Input vector dimension mismatch")

class LSHService:
    def __init__(self, dimension: int, num_tables: int = 5, hash_size: int = 10):
        self.dimension = dimension
        self.num_tables = num_tables
        self.hash_size = hash_size
        self.tables: List[Dict[str, List[List[float]]]] = [defaultdict(list) for _ in range(num_tables)]
        self.random_planes = [np.random.randn(dimension) for _ in range(num_tables * hash_size)]

    def _hash_vector(self, vector: List[float]) -> List[str]:
        hashes = []
        for i in range(self.num_tables):
            hash_str = ""
            for j in range(self.hash_size):
                idx = i * self.hash_size + j
                projection = np.dot(vector, self.random_planes[idx])
                hash_str += '1' if projection >= 0 else '0'
            hashes.append(constant_time_hash(hash_str))
        return hashes

    @rate_limit(max_calls=100, time_frame=60)
    def add_vector(self, vector: List[float], identifier: str) -> None:
        validate_input(vector, self.dimension)
        hashes = self._hash_vector(vector)
        for i in range(self.num_tables):
            self.tables[i][hashes[i]].append((vector, identifier))

    @rate_limit(max_calls=100, time_frame=60)
    def query_nearest(self, vector: List[float], k: int = 1) -> List[Dict[str, Any]]:
        validate_input(vector, self.dimension)
        hashes = self._hash_vector(vector)
        candidates = set()

        for i in range(self.num_tables):
            bucket = self.tables[i].get(hashes[i], [])
            for v, ident in bucket:
                candidates.add((ident, np.linalg.norm(np.array(vector) - np.array(v))))

        sorted_candidates = sorted(candidates, key=lambda x: x[1])[:k]
        return [{"identifier": ident, "distance": dist} for ident, dist in sorted_candidates]
