```cpp
#include <atomic>
#include <vector>
#include <thread>
#include <iostream>
#include <x86intrin.h>
#include <numa.h>
#include <sys/mman.h>
#include <algorithm>
#include <chrono>

constexpr int MAX_ORDERS = 1'000'000;
constexpr int PRICE_LEVELS = 10'000;
constexpr int NUM_THREADS = 4;

struct Order {
    uint64_t id;
    bool is_buy;
    uint32_t price;
    uint32_t quantity;
    std::atomic<Order*> next;
};

struct PriceLevel {
    std::atomic<Order*> head;
    std::atomic<uint32_t> total_quantity;
};

class LockFreeAllocator {
public:
    LockFreeAllocator(size_t size) {
        void* ptr = mmap(NULL, size, PROT_READ|PROT_WRITE, 
                        MAP_PRIVATE|MAP_ANONYMOUS|MAP_HUGETLB, -1, 0);
        if (ptr == MAP_FAILED) {
            throw std::bad_alloc();
        }
        pool = static_cast<char*>(ptr);
        pool_size = size;
        current.store(0, std::memory_order_relaxed);
    }

    void* allocate(size_t size) {
        size_t offset = current.fetch_add(size, std::memory_order_relaxed);
        if (offset + size > pool_size) {
            throw std::bad_alloc();
        }
        return pool + offset;
    }

private:
    char* pool;
    size_t pool_size;
    std::atomic<size_t> current;
};

class MatchingEngine {
public:
    MatchingEngine() : 
        buy_levels(PRICE_LEVELS), 
        sell_levels(PRICE_LEVELS),
        allocator(MAX_ORDERS * sizeof(Order)) {

        for (int i = 0; i < PRICE_LEVELS; ++i) {
            buy_levels[i].head.store(nullptr, std::memory_order_relaxed);
            sell_levels[i].head.store(nullptr, std::memory_order_relaxed);
        }
    }

    void process_order(Order* order) {
        if (order->is_buy) {
            process_buy(order);
        } else {
            process_sell(order);
        }
    }

private:
    void process_buy(Order* buy_order) {
        for (int price = buy_order->price; price < PRICE_LEVELS && buy_order->quantity > 0; ++price) {
            PriceLevel& level = sell_levels[price];
            Order* sell_head = level.head.load(std::memory_order_acquire);

            while (sell_head && buy_order->quantity > 0) {
                uint32_t match_qty = std::min(buy_order->quantity, sell_head->quantity);

                // Execute trade
                buy_order->quantity -= match_qty;
                sell_head->quantity -= match_qty;
                level.total_quantity.fetch_sub(match_qty, std::memory_order_relaxed);

                if (sell_head->quantity == 0) {
                    Order* next = sell_head->next.load(std::memory_order_relaxed);
                    level.head.compare_exchange_strong(sell_head, next, std::memory_order_release);
                    // Recycle order
                } else {
                    break;
                }

                sell_head = level.head.load(std::memory_order_acquire);
            }
        }

        if (buy_order->quantity > 0) {
            add_to_book(buy_order, buy_levels[buy_order->price]);
        }
    }

    void process_sell(Order* sell_order) {
        for (int price = sell_order->price; price >= 0 && sell_order->quantity > 0; --price) {
            PriceLevel& level = buy_levels[price];
            Order* buy_head = level.head.load(std::memory_order_acquire);

            while (buy_head && sell_order->quantity > 0) {
                uint32_t match_qty = std::min(sell_order->quantity, buy_head->quantity);

                // Execute trade
                sell_order->quantity -= match_qty;
                buy_head->quantity -= match_qty;
                level.total_quantity.fetch_sub(match_qty, std::memory_order_relaxed);

                if (buy_head->quantity == 0) {
                    Order* next = buy_head->next.load(std::memory_order_relaxed);
                    level.head.compare_exchange_strong(buy_head, next, std::memory_order_release);
                    // Recycle order
                } else {
                    break;
                }

                buy_head = level.head.load(std::memory_order_acquire);
            }
        }

        if (sell_order->quantity > 0) {
            add_to_book(sell_order, sell_levels[sell_order->price]);
        }
    }

    void add_to_book(Order* order, PriceLevel& level) {
        Order* old_head = level.head.load(std::memory_order_relaxed);
        order->next.store(old_head, std::memory_order_relaxed);

        while (!level.head.compare_exchange_weak(
            old_head, order, 
            std::memory_order_release, 
            std::memory_order_relaxed)) {
            order->next.store(old_head, std::memory_order_relaxed);
        }

        level.total_quantity.fetch_add(order->quantity, std::memory_order_relaxed);
    }

    std::vector<PriceLevel> buy_levels;
    std::vector<PriceLevel> sell_levels;
    LockFreeAllocator allocator;
};

void pin_thread(int cpu) {
    cpu_set_t cpuset;
    CPU_ZERO(&cpuset);
    CPU_SET(cpu, &cpuset);
    pthread_setaffinity_np(pthread_self(), sizeof(cpu_set_t), &cpuset);
}

void benchmark() {
    MatchingEngine engine;
    std::vector<std::thread> threads;

    auto start = std::chrono::high_resolution_clock::now();

    for (int i = 0; i < NUM_THREADS; ++i) {
        threads.emplace_back([&engine, i]() {
            pin_thread(i);

            for (int j = 0; j < MAX_ORDERS/NUM_THREADS; ++j) {
                Order* order = static_cast<Order*>(engine.allocator.allocate(sizeof(Order)));
                order->id = j;
                order->is_buy = (j % 2) == 0;
                order->price = j % PRICE_LEVELS;
                order->quantity = 100;
                engine.process_order(order);
            }
        });
    }

    for (auto& t : threads) {
        t.join();
    }

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

    std::cout << "Processed " << MAX_ORDERS << " orders in " << duration << " ns\n";
    std::cout << "Average latency: " << duration/MAX_ORDERS << " ns/order\n";
    std::cout << "Throughput: " << (MAX_ORDERS * 1e9) / duration << " orders/sec\n";
}

int main() {
    benchmark();
    return 0;
}
