        let mut pending = self.pending_messages.lock().unwrap();
        if pending.contains(&msg.id) {
            return false;
        }

        pending.insert(msg.id);
        let mut wal = self.write_ahead_log.lock().unwrap();
        wal.push(msg);
        true
    }

