const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const redis = require('redis');
const cluster = require('cluster');
const numCPUs = require('os').cpus().length;
const sticky = require('sticky-session');

// Redis Pub/Sub setup
const redisClient = redis.createClient({ host: 'redis', port: 6379 });
const redisPublisher = redis.createClient({ host: 'redis', port: 6379 });

if (cluster.isMaster) {
  console.log(`Master ${process.pid} is running`);

  // Fork workers
  for (let i = 0; i < numCPUs; i++) {
    cluster.fork();
  }

  cluster.on('exit', (worker) => {
    console.log(`Worker ${worker.process.pid} died`);
    cluster.fork();
  });
} else {
  const app = express();
  const server = http.createServer(app);

  // Sticky session setup
  if (!sticky.listen(server, 3000)) {
    server.once('listening', () => {
      console.log(`Worker ${process.pid} listening`);
    });
  } else {
    const io = socketIo(server, {
      cors: {
        origin: "*",
        methods: ["GET", "POST"]
      }
    });

    // Socket.IO with Redis adapter
    const redisAdapter = require('socket.io-redis');
    io.adapter(redisAdapter({ host: 'redis', port: 6379 }));

    // Handle connections
    io.on('connection', (socket) => {
      console.log(`Client connected on worker ${process.pid}`);

      socket.on('message', (data) => {
        // Publish message to Redis channel
        redisPublisher.publish('chat', JSON.stringify(data));
      });

      socket.on('disconnect', () => {
        console.log(`Client disconnected from worker ${process.pid}`);
      });
    });

    // Subscribe to Redis channel
    redisClient.subscribe('chat');
    redisClient.on('message', (channel, message) => {
      if (channel === 'chat') {
        // Broadcast to all clients
        io.emit('message', JSON.parse(message));
      }
    });
  }
}

