// app.component.ts
import { Component, HostListener, OnInit } from '@angular/core';
import { CdkDragDrop, moveItemInArray } from '@angular/cdk/drag-drop';
import { MatSnackBar } from '@angular/material/snack-bar';
import { OnlineStatusService } from './online-status.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  widgets: any[] = [];
  isLoading = true;
  isOnline = true;

  constructor(
    private snackBar: MatSnackBar,
    private onlineStatusService: OnlineStatusService
  ) {}

  ngOnInit() {
    this.loadLayout();
    this.checkOnlineStatus();

    setTimeout(() => {
      this.isLoading = false;
    }, 1500);
  }

  @HostListener('window:keydown', ['$event'])
  handleKeyboardEvent(event: KeyboardEvent) {
    if (event.ctrlKey && event.key === 's') {
      event.preventDefault();
      this.saveLayout();
    }
  }

  drop(event: CdkDragDrop<string[]>) {
    moveItemInArray(this.widgets, event.previousIndex, event.currentIndex);
  }

  saveLayout() {
    localStorage.setItem('dashboardLayout', JSON.stringify(this.widgets));
    this.snackBar.open('Layout saved!', 'Dismiss', { duration: 2000 });
  }

  loadLayout() {
    const savedLayout = localStorage.getItem('dashboardLayout');
    if (savedLayout) {
      this.widgets = JSON.parse(savedLayout);
    } else {
      // Default widgets
      this.widgets = [
        { id: 1, type: 'chart', title: 'Portfolio Value', size: 'medium' },
        { id: 2, type: 'chart', title: 'Asset Allocation', size: 'small' },
        { id: 3, type: 'widget', title: 'Recent Transactions', size: 'large' },
        { id: 4, type: 'widget', title: 'Watchlist', size: 'small' }
      ];
    }
  }

  checkOnlineStatus() {
    this.onlineStatusService.status.subscribe(isOnline => {
      this.isOnline = isOnline;
      if (!isOnline) {
        this.snackBar.open('You are offline. Some features may not work.', 'Dismiss');
      }
    });
  }

  resizeWidget(widget: any, size: string) {
    widget.size = size;
  }
}
