```go
package main

import (
	"context"
	"log"
	"sync"
	"time"
	"unsafe"

	"github.com/ffmpeg-go/ffmpeg"
	"github.com/ffmpeg-go/n6avcodec"
	"github.com/ffmpeg-go/n6avformat"
	"github.com/ffmpeg-go/n6avutil"
)

const (
	maxWorkers       = 4
	targetLatency    = 500 * time.Millisecond
	segmentDuration  = 2 * time.Second
	bitrateVariants  = "1200k:800k:400k"
	bufferSize       = 1024 * 1024 // 1MB zero-copy buffer
)

type Transcoder struct {
	workerPool chan struct{}
	gpuCtx     *n6avcodec.Context
	inputBuf   []byte
	outputBuf  []byte
}

func NewTranscoder() *Transcoder {
	// Initialize GPU context with CUDA
	gpuCtx := n6avcodec.NewContext()
	if err := gpuCtx.InitCUDA(); err != nil {
		log.Fatal("CUDA init failed:", err)
	}

	return &Transcoder{
		workerPool: make(chan struct{}, maxWorkers),
		gpuCtx:     gpuCtx,
		inputBuf:   make([]byte, bufferSize),
		outputBuf:  make([]byte, bufferSize),
	}
}

func (t *Transcoder) ProcessSegment(segment []byte) []byte {
	// Wait for worker slot
	t.workerPool <- struct{}{}
	defer func() { <-t.workerPool }()

	// Zero-copy to GPU memory
	inputPtr := unsafe.Pointer(&segment[0])
	n6avutil.Memcpy(unsafe.Pointer(&t.inputBuf[0]), inputPtr, len(segment))

	// GPU-accelerated transcoding
	start := time.Now()
	output := t.transcodeOnGPU()
	latency := time.Since(start)

	if latency > targetLatency {
		log.Printf("Latency warning: %v", latency)
	}

	return output
}

func (t *Transcoder) transcodeOnGPU() []byte {
	// FFmpeg GPU transcoding pipeline
	args := []string{
		"-hwaccel", "cuda", "-hwaccel_output_format", "cuda",
		"-i", "pipe:0",
		"-c:v", "h264_nvenc",
		"-b:v", bitrateVariants,
		"-f", "h264", "pipe:1",
	}

	cmd := ffmpeg.Command(args...)
	cmd.Stdin = bytes.NewReader(t.inputBuf)
	var out bytes.Buffer
	cmd.Stdout = &out

	if err := cmd.Run(); err != nil {
		log.Fatal("FFmpeg error:", err)
	}

	return out.Bytes()
}

func main() {
	transcoder := NewTranscoder()
	var wg sync.WaitGroup

	// Simulate video stream segments
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(segNum int) {
			defer wg.Done()
			segment := make([]byte, bufferSize/2) // Simulate 720p segment
			result := transcoder.ProcessSegment(segment)
			log.Printf("Segment %d transcoded (%d bytes)", segNum, len(result))
		}(i)
	}

	wg.Wait()
}
